INSERT INTO `categorias` (`ID_CATEGORIA`, `CATEGORIA_NOMBRE`, `URL`, `CATEGORIA_DESCRIPCION`, `IMAGEN`, `CATEGORIA_PADRE`, `CATEGORIA_NIVEL`, `VISIBLE`, `TIPO`, `ESTADO`, `ORDEN`, `DESTACADA`) VALUES
	(4, 'Sistemas de Reiki', 'sistemas-de-reiki', '<p>En este curso te convertirás en un transmisor puro de vibración de Reiki la cual usarás para sanar cuerpo, mente, e incrementar tu desarrollo espiritual. Reiki te permitirá conocer quién eres realmente. </p><p><br>Cuando nos referimos a la energía universal de la más alta vibración, es cuando decimos Reiki. Es una palabra japonesa que utilizó el maestro Mikao Usui para distinguirla de otras energías, y significa Energía del Universo. El maestro Usui creó un método para utilizarla y lo llamó Usui Reiki Ryoho.</p><p><br>En Reiki existen todas las respuestas para brillar interiormente. La luz de Reiki te será otorgada ilimitadamente, pero la recibirás de acuerdo a tu propio entendimiento y aceptación. La clave está en cómo entiendes el concepto de Reiki y sus técnicas, en esa proporción recibirás su amor.</p><p><br>Reiki es la energía universal de la más alta dimensión, y lleva consigo las propiedades de las ondas de amor, armonía y sanación. El amor es la esencia del Universo, la armonía es su voluntad y la sanación es su efecto.<br>Con el uso continuo de Reiki, podemos ayudarnos a nosotros mismo y a otras personas a sanar todo tipo de enfermedades. En un tratamiento de Reiki, se recupera la condición armoniosa entre la mente y el cuerpo. Actúa de manera natural fortaleciendo el sistema inmunológico, activando el sistema natural de sanación y la energía vital.</p><p><br>En un tratamiento la energía se aplica con las manos, todo el cuerpo del practicante de Reiki emana Luz, principalmente las manos, lo ojos y la boca. De manera natural actúa sanando en el cuerpo mental, emocional y físico.</p><p><br></p><p>Existen diferentes tipos de sistemas en Reiki Tamashi impartimos 5<br></p><ul><li>Reiki Japones</li><li>Reiki Angélico</li><li>Reiki Tibetano-Tántrico</li><li>Reiki Egipcio</li><li>Reiki Karuna<br><br>Acércate a nosotros y pide tu cita y con gusto te explicamos como puedes empezar a aprender las diferentes técnicas para que tu vida cambie de manera maravillosa y extraordinaria<br><br>Puedes pedir tu cita en el Whatsapp&nbsp; 55-16-44-34-52<br><br></li></ul>', 'categoria-5cfb6912309a9.jpg', 0, 1, 'visible', 'curso_reiki', 'activo', 0, 0),
	(5, 'Reiki Japonés ', 'reiki-japones-mcnt', '<p class="MsoNormal"><span style="background-color: rgb(140, 123, 198);"></span>Los cursos de Reiki son una técnica de sanación a través de\r\nla canalización de energía por imposición de las manos, misma que ha sido\r\nutilizada en diferentes civilizaciones, de igual modo el uso de símbolos ha\r\nestado presente a lo largo de la historia de la humanidad. Conozca más acerca\r\nde nuestros diferentes cursos de Reiki.<o:p></o:p></p>', 'categoria-5cfbdc63447ab.jpg', 4, 2, 'visible', 'curso_reiki', 'activo', 0, 0),
	(6, 'Especialidades de cursos de Reiki', 'especialidades-de-cursos-de-reiki', '<p class="MsoNormal">Los cursos de Reiki son una técnica de sanación a través de\r\nla canalización de energía por imposición de las manos, misma que ha sido\r\nutilizada en diferentes civilizaciones, de igual modo el uso de símbolos ha\r\nestado presente a lo largo de la historia de la humanidad. Conozca más acerca\r\nde nuestros diferentes cursos de Reiki:<o:p></o:p></p>', 'categoria-5cfbdc95a0335.jpg', 4, 2, 'visible', 'curso_reiki', 'activo', 5, 0),
	(7, 'Galerias', 'galerias', '', 'categoria-5dbb9fa43ce5c.jpg', 0, 1, 'visible', 'galeria', 'activo', 0, 0),
	(10, 'pagina de inicio', 'pagina-de-inicio', '', 'default.jpg', 0, 1, 'invisible', 'promocion', 'activo', 0, 0),
	(11, 'Información', 'informacion', '', 'categoria-5cfc55c8bc76b.jpg', 0, 1, 'visible', 'pagina', 'activo', 0, 0),
	(12, 'Terapias', 'terapias', '', 'categoria-5cfc55d916bd7.jpg', 0, 1, 'visible', 'terapia', 'activo', 0, 1),
	(15, 'Más Cursos', 'mas-cursos', '', 'categoria-5cfc62742d9e4.jpg', 0, 1, 'visible', 'cursos', 'activo', 0, 1),
	(17, 'Artículos', 'articulos', '', 'categoria-5cfc6a220b3cf.jpg', 0, 1, 'visible', 'articulo', 'activo', 0, 0),
	(18, 'Egresados', 'egresados', '', 'categoria-5cfca2a7d1c3e.jpg', 0, 1, 'visible', 'egresado', 'activo', 0, 0),
	(19, 'Reiki Angélico', 'reiki-angelico', '<h5><br></h5><p class="MsoNormal">Una vez realizada la maestría en Reiki Japonés Tradicional\r\nse recomienda continuar la formación de cursos de Reiki con el sistema de\r\nAngélico.</p><p class="MsoNormal"> </p><p class="MsoNormal">Esta maestría de cursos de Reiki toma como base la enseñanza\r\nde Reiki Japonés en los cuatro primeros niveles. Este curso de reiki tiene como\r\nobjetivo trabajar mano a mano con el Reino Angélico de luz para traer una de\r\nlas formas más elevadas de sanación para individuos, grupos y el planeta. Los\r\nÁngeles son Maestros, los ascendidos del universo, a través de su guía el arte\r\nsanador de Reiki puede actuar en el ser a nivel menta, emocional y físico.</p><p class="MsoNormal"> </p><h5>¿A quién van dirigidos los cursos de Reiki Angélico?</h5><p class="MsoNormal">A todas las personas que les interese conocer el mundo\r\nAngélico y utilizar símbolos angélicos para llevar a cabo una sanación más\r\nprofunda y eficaz ayudados de los maestros Ascendidos.</p><p class="MsoNormal"> </p><h5>Requisitos</h5><ul><li>Haber cursado cuarto nivel de Reiki Japones</li><li>Ser mayor de 13 años</li><li>En caso de ser menor de 18 años estar acompañado de un\r\nadulto o firmar carta autorización de Padres o tutor.</li><li>Firmar reglamento.</li></ul><p class="MsoNormal"> </p><h5>TEMAS</h5><ul><li>Quienes son los Ángeles </li><li>Invocación a Ángeles </li><li>Chacras y Ángeles </li><li>Ángeles, colores y peticiones </li><li>Sanando como un canal de energía Angélica</li><li>Mantras </li><li>Símbolos Angélicos</li><li>Circulo de sanación</li></ul><p class="MsoNormal"> </p><h5>Duración</h5><p class="MsoNormal">28 horas, divididas en 7 clases de 4 horas diarias.</p><p class="MsoNormal"> </p><h5>Todos los cursos de Reiki Angélico incluyen:</h5><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class="MsoNormal">Manual del curso, CD de música y Meditación del nivel,\r\nConstancia del Nivel.</p>', 'categoria-6716fac0d412b.jpg', 4, 2, 'visible', 'curso_reiki', 'activo', 1, 0),
	(20, 'Reiki Tibetano-Tántrico', 'reiki-tibetano-tantrico', '<h5><br></h5><p class="MsoNormal">Una vez realizada la maestría en Reiki Japonés Tradicional\r\nse recomienda continuar la formación de cursos de Reiki con el Sistema\r\nTibetano-Tántrico.</p><p class="MsoNormal">&nbsp;</p><p class="MsoNormal">Esta maestría de cursos de reiki toma como base la enseñanza\r\nde Reiki Japonés en los cuatro primeros niveles, enseñando a nivel maestría 11\r\nsímbolos complementarios que permiten llegar a profundidad en la sanación del\r\ncuerpo, mente y energía. Los símbolos tibetanos forman parte del TANTRA, que es\r\nel sistema por el cual purificamos y transformamos, nuestras emociones\r\nconflictos, cuya base es la ignorancia. Con el uso de los símbolos, se\r\ndesarrolla la sabiduría y se nos permite percibir el estado puro del alma. Los\r\nsímbolos tántricos, a diferencia de otros símbolos, se introducen directamente\r\nen los chacras a través del sushumna o canal central, por el chacra corona.\r\nCuando despierta la kundalini, que permanece enroscada en una espiral en forma\r\nde serpiente en la base de la columna, se eleva a través del sushumna para unir\r\nel chacra corona con la divinidad, descrita como la conciencia pura.</p><p class="MsoNormal">&nbsp;</p><h5>¿A quién van dirigidos los cursos de Reiki\r\nTibetano-Tántrico?</h5><p class="MsoNormal">A todas las personas que esten interesadas en conocer\r\nsímbolos tántricos-tibetanos para llevar a cabo una sanación más profunda y\r\neficaz. Como requisito de admisión deberá haber cursado Maestría Gokuidaiden\r\nReiki Japonés, firmar reglamento y ser mayor de 13 años o estar acompañado de\r\nun adulto.</p><p class="MsoNormal">&nbsp;</p><p class="MsoNormal">TEMAS</p><ul><li>Meditación de la Maestría de Reiki </li><li>Símbolos de la maestría del sistema Tibetano-tantrico </li><li>Iniciaciones</li><li>Tratamiento de Reiki a nivel Maestría</li></ul><p class="MsoNormal">&nbsp;</p><h5>Requisitos</h5><ul><li>Haber cursado cuarto nivel de Reiki Japones</li><li>Ser mayor de 13 años</li><li>En caso de ser menor de 18 años estar acompañado de un\r\nadulto o firmar carta autorización de Padres o tutor.</li><li>Firmar reglamento.</li></ul><p class="MsoNormal">&nbsp;</p><h5>Duración</h5><p class="MsoNormal">28 horas, divididas en 7 clases de 4 horas diarias.</p><p class="MsoNormal">&nbsp;</p><h5>Todos los cursos de Reiki Tibetano-Tántrico incluyen:</h5><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p>Manual del curso, CD de música y Meditación del nivel,\r\nConstancia del Nivel', 'categoria-5cfd9c0583794.jpg', 4, 2, 'visible', 'curso_reiki', 'activo', 2, 0),
	(21, 'Reiki Karuna', 'reiki-karuna', '<h5><br></h5><p class="MsoNormal">El sistema Reiki Karuna Prakriti es conocido como la\r\nMaestría de Maestrías por el alto nivel vibratorio que se utiliza en los\r\nsímbolos.</p><p class="MsoNormal">El sistema fue desarrollado por William L. Rand en\r\ncolaboración de otros maestros de Reiki y básicamente se trabaja con el “Mara”\r\nque es la parte oscura que podemos llegar a tener y con el uso de los símbolos\r\nKaruna podemos sanar y limpiar.</p><p class="MsoNormal"> </p><h5>Requisitos</h5><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p>Para poder estudiar este sistema de la compasión es\r\nnecesario tener la maestría de algún otro sistema para poder entender y\r\nasimilar la energía sanadora de sus símbolos, consta de Dos niveles, Practicante\r\ny Maestría: En el primero se enseñan 15 nuevos símbolos y en la Maestría 6 para\r\ngenerar un dominio del Mara. El conocimiento se complementa con Meditaciones de\r\nalta vibración, símbolos anthakarana, Sanación con el Rayo Violeta, y\r\nprotección del Circulo de Fuego azul.', 'categoria-6184947d9fe15.jpg', 4, 2, 'visible', 'curso_reiki', 'activo', 3, 0),
	(24, 'Reiki Egipcio', 'reiki-egipcio', '<p>El sistema Reiki Egipcio solo consta de Nivel Maestría, tiene como requisito indispensable tener Maestría en Reiki Japonés o Tibetano-Tántrico<br><br>El sistema de Reiki Egipcio trabaja con la energía Seichim es energía de luz espiritual sanadora que los egipcios utilizaron y fueron enseñados en los tiempos de Egipto antiguo. Redescubierto en los años 80 por el maestro Patrick Zeigler en un viaje a la tierra de las pirámides recibió la orientación cósmica de permanecer una noche en la cámara del faraón de la gran pirámide. Allí entro en un estado de meditación en un determinado momento comenzó a sentir en una forma creciente vibraciones provenientes de otras cámaras, estas vibraciones energéticas se concentraron hacia el chacra de su corazón y que penetraba en su cuerpo etérico sanándolo y transformándolo en un sanador. Sin embargo, él no entendía cómo a partir de esta iniciación bastaba que colocase sus manos en el chacra del corazón para percibir las vibraciones.</p><p><br>El reiki egipcio o el sistema Seichim es un antiguo sistema egipcio de sabiduría sanadora que busca equilibrar y armonizar los distintos planos del cuerpo (el físico, el emocional, el mental y el espiritual).</p><p><br>Por tanto no es propiamente una vertiente del reiki, sino que más bien utiliza el reiki como herramienta para trabajar.</p><p><br>La cultura egipcia siempre fue una fuente de aprendizaje en el terreno espiritual pues se la considera como una de las que más trabajó en ese terreno.</p><p><br>SEICHIM SEICHEM REIKI, más conocido como Reiki Egipcio, es la unión de Seichim (Energía luminosa de Vida) y Reiki con otra energía universal conocida como Sekhem (Fuerza o poder). Todas ellas son originarias de una Fuente única que emana del orígen primigenio del AMOR SUPREMO</p><p><br>Son diamantes con muchas facetas, que unidas, se complementan. Este sistema es un milagro y es infinito en su capacidad para guiarnos y navegar en nuestro camino de vuelta a casa, hacia la Fuente del Amor Absoluto.</p><p><br>Nos lleva a un estado de conciencia unificada donde Todo es Uno y Uno es Todo, sintiendo la PRESENCIA del YO SOY desde la Conciencia Crística.</p><p><br>Esta energía está en nuestro Presente para ayudarnos a recordar y despertar nuestro Ser desde el Amor Divino, el Poder y la Sabiduría.</p><p><br>Actúa como una Trinidad Unificada y Sagrada para la sanación, equilibrando y armonizando a cada persona y todos sus cuerpos, expandiendo la capacidad de contener y canalizar energía unificada Cielo y Tierra a través de la Columna de Luz y el Corazón Unificado del Corazón.</p><p><br>SSR aporta Renacimiento a las personas iniciadas por esta bella energía.<br>Su origen está relacionado con los conocimientos de las antiguas escuelas de misterios y templos de la Lemuria, Atlántida, Egipto, Tíbet e India. Estas enseñanzas han vuelto a la Tierra para el surgimiento de una nueva era y el despertar de la divinidad interior.</p><p><br>El sistema contiene símbolos sagrados. Su poderosa iniciación produce un profundo efecto de despertar espiritual y de preparación para el proceso de ascensión.<br>Sekhem significa «Poder de Poderes». Este sistema ofrece poderosas herramientas para conectar con el Ser Superior y la Fuente del Amor <br>Supremo.<br><br>Temario General:<br>•&nbsp;&nbsp;&nbsp; Sistema de energía Humana<br>•&nbsp;&nbsp;&nbsp; Energía Kundalini<br>•&nbsp;&nbsp;&nbsp; La columna central de luz<br>•&nbsp;&nbsp;&nbsp; Los 14 símbolos y su uso<br>•&nbsp;&nbsp;&nbsp; Entretejido de Luz Angelical<br>•&nbsp;&nbsp;&nbsp; Cordones Energéticos<br>•&nbsp;&nbsp;&nbsp; Sanación a distancia<br>•&nbsp;&nbsp;&nbsp; Sellando Lesiones aúricas<br>•&nbsp;&nbsp;&nbsp; Sanación por sonido<br>•&nbsp;&nbsp;&nbsp; Protección del círculo de fuego azul<br>•&nbsp;&nbsp;&nbsp; Iniciaciones<br><br></p>', 'categoria-6365f4e7e7b70.jpg', 4, 2, 'visible', 'curso_reiki', 'activo', 4, 0),
	(25, 'Cambio de nombre', 'prueba_home', '<p>Hola mundo</p>', 'categoria-ee6c2645-7f31-49b1-98ee-e03113d17819.webp', 0, 1, 'visible', 'promocion', 'activo', 0, 0),
	(26, 'Segundo nivel', 'segundo-nivel', '<p>Descripción</p>', 'categoria-760d212f-8c4a-4f41-b8b6-c99f067becfe.webp', 25, 2, 'visible', 'promocion', 'activo', 0, 0);
