INSERT INTO `publicaciones` (`ID_PUBLICACION`, `PUBLICACION_TITULO`, `URL`, `PUBLICACION_RESUMEN`, `PUBLICACION_CONTENIDO`, `IMAGEN`, `PUBLICACION_PADRE`, `FECHA_REGISTRO`, `FECHA_ACTUALIZACION`, `FECHA_PUBLICACION`, `TIPO`, `ESTADO`, `ORDEN`, `DESTACADA`) VALUES
	(1, 'Acerca de Nosotros', 'acerca-de-nosotros', 'Somos una institución que busca la concientización integral del ser humano en sus ámbitos mental, espiritual, emocional y físico.', '<h1 class="tituloCentrado" style="text-align: justify; margin: 20px 0px 10px; line-height: 1.1;">Tamashi</h1><h4 class="tituloCentrado" style="font-family: " helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" line-height:="" 1.1;="" color:="" rgb(51,="" 51,="" 51);="" margin-top:="" 10px;="" margin-bottom:="" font-size:="" 18px;="" text-align:="" center;"=""></h4><h3 class="tituloCentrado" style="text-align: left; line-height: 1.1; margin-top: 20px; margin-bottom: 10px;"><span style="font-size: 18px;">Somos una institución que busca la concientización integral del ser humano en sus ámbitos mental, espiritual, emocional y físico.</span></h3><h3 class="tituloCentrado" style="text-align: justify; line-height: 1.1; margin-top: 20px; margin-bottom: 10px;"><span style="text-align: left;">Centro Holístico y Terapéutico Tamashi</span></h3><p style="text-align: justify; margin-right: 0px; margin-bottom: 10px; margin-left: 0px;" helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;"="">Centro Holístico y Terapéutico Tamashi fue creado con la finalidad de poner al alcance de todos terapias alternativas de sanación tanto física pero sobre todo espiritual. Es un centro de Amor, Luz y Conocimiento profundo hacia el ser humano.</p><h3 class="tituloCentrado" style="text-align: justify; line-height: 1.1; margin-top: 20px; margin-bottom: 10px;">Misión</h3><p style="text-align: justify; margin-right: 0px; margin-bottom: 10px; margin-left: 0px;" helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;"="">El Centro Holístico y Terapéutico Tamashi es un centro de amor, luz y conocimiento profundo hacia el ser humano, que fue creado con la finalidad de poner al alcance de todas las personas, sin hacer distinción alguna, terapias alternativas de sanación tanto físicas como espirituales y brindar conocimiento a través de talleres y cursos de desarrollo espiritual.</p><h3 class="tituloCentrado" style="text-align: justify; line-height: 1.1; margin-top: 20px; margin-bottom: 10px;">Visión</h3><p style="text-align: justify; margin-right: 0px; margin-bottom: 10px; margin-left: 0px;" helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;"="">Actualmente el Centro Holístico y Terapéutico Tamashi es un centro que brinda apoyo emocional y espiritual a todas las personas que lo necesitan cuya visión es que mediante el compromiso, trabajo duro, renovación y constantes aprendizajes y capacitación se convierta en una primera opción, un centro altamente confiable y líder entre los centros holísticos y terapéuticos por sus aportaciones a la espiritualidad.</p><h3 class="tituloCentrado" style="text-align: justify; line-height: 1.1; margin-top: 20px; margin-bottom: 10px;">Valores</h3><p style="text-align: justify; margin-right: 0px; margin-bottom: 10px; margin-left: 0px;" helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;"="">Los valores del Centro Holístico y Terapéutico Tamashi son los pilares que nos sostienen como organización y que nos guían en nuestra misión.</p><ul style="margin-bottom: 10px;" helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;"=""><li style="text-align: justify; ">Espiritualidad</li><li style="text-align: justify; ">Ética</li><li style="text-align: justify; ">Honestidad</li><li style="text-align: justify; ">Compromiso</li><li style="text-align: justify; ">Objetividad</li><li style="text-align: justify; ">Conocimiento</li><li style="text-align: justify; ">Profesionalismo</li><li style="text-align: justify; ">Integridad</li><li style="text-align: justify; ">Respeto</li></ul>', 'publicacion-5cfb5c8b938a5.jpg', 0, '2019-06-08 06:00:00', '2021-10-17 17:48:56', '2019-06-08 06:00:00', 'pagina', 'activo', 0, 0),
	(2, 'Mandalas', 'mandalas', 'Los Mándalas actúan equilibrando los chacras por medio de los colores y haciendo meditar el lado lógico de nuestro cerebro a través de las formas geométricas sagradas. El Mándala enviará impulsos a la mente interna llegando a los receptores del cerebro donde se procesará y se obtendrá una reacción sanadora.', '<p style="margin-right: 0px; margin-bottom: 10px; margin-left: 0px; color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Los Mándalas actúan equilibrando los chacras por medio de los colores y haciendo meditar el lado lógico de nuestro cerebro a través de las formas geométricas sagradas. El Mándala enviará impulsos a la mente interna llegando a los receptores del cerebro donde se procesará y se obtendrá una reacción sanadora.</p><p style="margin-right: 0px; margin-bottom: 10px; margin-left: 0px; color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Los mándalas son útiles para la concentración, activación de la energía positiva, energización de lugares, meditación profunda para elevar el nivel de conciencia, expandir la capacidad de la mente y la memoria.</p><p style="margin-right: 0px; margin-bottom: 10px; margin-left: 0px; color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Los mándalas pueden ayudarte en el equilibrio de los chacras, en ese caso habrá que elegir el color adecuado dependiendo de la cualidad que se quiere trabajar, El mándala enviará impulsos a la mente interna llegando a los receptores del cerebro en donde se procesará y se obtendrá una reacción.</p><p style="margin-right: 0px; margin-bottom: 10px; margin-left: 0px; color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Son muchos los beneficios que podemos tomar de un mándala, lo mínimo que puede hacer por nosotros es ayudarnos a centrarnos cuando sufrimos de alguna alteración nerviosa, nos ayuda a relajarnos y a encontrar la paz en medio de las dificultades y eso en medio de un mundo tan complejo y conflictivo.</p><p style="margin-right: 0px; margin-bottom: 10px; margin-left: 0px; color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Cromoterapia: Un mándala siempre va a ser positivo sea cual sea su color, pero resulta doblemente útil cuando nosotros ya hemos localizado algún color determinado, el cual actuaria de manera directa acelerando el proceso de curación.</p>', 'publicacion-5cfc5533ccc09.jpg', 0, '2019-06-08 06:00:00', '2025-07-04 00:43:57', '2019-06-08 06:00:00', 'cursos', 'inactivo', 15, 0),
	(3, 'Reiki Japonés Nivel I Despertar a la luz', 'reiki-japones-nivel-i-despertar-a-la-luz', 'En este módulo del nivel 1 de nuestros cursos de reiki, tendremos el objetivo de sintonizar al alumno con la energía de Reiki y comenzar con la autosanación conociendo la energía que fluye en nuestro cuerpo.', '<h5>Módulo 1</h5><p class="MsoNormal"><o:p></o:p></p>\r\n\r\n<p class="MsoNormal">En este módulo del nivel 1 de nuestros cursos de reiki,\r\ntendremos el objetivo de sintonizar al alumno con la energía de Reiki y\r\ncomenzar con la autosanación conociendo la energía que fluye en nuestro cuerpo.<o:p></o:p></p>\r\n\r\n<h5><o:p>&nbsp;</o:p><span style="font-size: 1.25rem;">TEMAS</span></h5><p class="MsoNormal"><o:p></o:p></p>\r\n\r\n<ul><li>&nbsp;Concepto de Reiki</li><li>Función\r\nde Reiki</li><li>Origen de las enfermedades</li><li>Historia de Mikao Usui </li><li>Principios de Reiki</li><li>Características de la\r\ntécnica </li><li>Kundalini</li><li>Chacras </li><li>Autotratamiento </li><li>Aura</li></ul>', 'publicacion-5cfb6cf793715.jpg', 0, '2019-06-08 06:00:00', '2026-04-04 22:41:11', '2019-06-08 06:00:00', 'curso_reiki', 'activo', 0, 1),
	(4, 'Reiki Japonés Modulo II', 'reiki-japones-modulo-ii', 'En el Módulo II de nuestros cursos de reiki, tendremos el objetivo de explicar los dones espirituales, y la aplicación de la técnica en otras personas, así como el uso de péndulo como herramienta de sanación.', '<p class="MsoNormal" align="center" style="text-align: left; margin-bottom: 7.5pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">En el Módulo II de nuestros cursos de reiki,\r\ntendremos el objetivo de explicar los dones espirituales, y la aplicación de la\r\ntécnica en otras personas, así como el uso de péndulo como herramienta de\r\nsanación.<o:p></o:p></p><h5 style="text-align: left; margin: 15pt 0cm 7.5pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">TEMAS</h5><p class="MsoNormal" align="center" style="text-align: left; margin: 15pt 0cm 7.5pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;"><o:p></o:p></p><ul><li style="text-align: left; margin-left: -3.75pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">Dones Espirituales</li><li style="text-align: left; margin-left: -3.75pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">Afirmaciones<o:p></o:p></li><li style="text-align: left; margin-left: -3.75pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">La meditación</li><li style="text-align: left; margin-left: -3.75pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">Tratamientos a otros<o:p></o:p></li><li style="text-align: left; margin-left: -3.75pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">Sanación de Sentimientos<o:p></o:p></li><li style="text-align: left; margin-left: -3.75pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">Técnicas de Sanación<o:p></o:p></li><li style="text-align: left; margin-left: -3.75pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">Uso de Reiki en la vida cotidiana</li><li style="text-align: left; margin-left: -3.75pt; line-height: normal; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">Péndulo<font color="#333333" face="Helvetica, sans-serif"><span style="font-size: 10.5pt;"><o:p></o:p></span></font></li></ul>', 'publicacion-5cfb6e2175a67.jpg', 0, '2019-06-08 06:00:00', '2021-11-05 01:33:06', '2019-06-08 06:00:00', 'curso_reiki', 'activo', 2, 0),
	(5, 'Reiki Japonés Nivel 2 Servidor de Luz', 'reiki-japones-nivel-2-servidor-de-luz', 'En el nivel 2 de nuestros cursos de reiki, tendremos el objetivo de aumentar la capacidad de sanación con el uso de símbolos de Reiki para realizar sanación de Karma y a distancia.', '<p style="margin-right: 0px; margin-bottom: 10px; margin-left: 0px;">En el nivel 2 de nuestros cursos de reiki, tendremos el objetivo de aumentar la capacidad de sanación con el uso de símbolos de Reiki para realizar sanación de Karma y a distancia.</p><h5 style="line-height: 1.1; margin-top: 20px; margin-bottom: 10px;">TEMAS</h5><ul><li style="margin-left: -21.75pt; line-height: normal;">Símbolos Reiki<o:p></o:p></li><li style="margin-left: -21.75pt; line-height: normal;">Sanación a Distancia<o:p></o:p></li><li style="margin-left: -21.75pt; line-height: normal;">Programación de Sanación a Distancia<o:p></o:p></li><li style="margin-left: -21.75pt; line-height: normal;">Grupo de Sanación a Distancia<o:p></o:p></li><li style="margin-left: -21.75pt; line-height: normal;">Rayos Luminosos<o:p></o:p></li><li style="margin-left: -21.75pt; line-height: normal;">Entrenamiento de Amor incondicional<o:p></o:p></li><li style="margin-left: -21.75pt; line-height: normal;">Sanación de pasado y proyección de\r\nfuturo<o:p></o:p></li><li style="margin-left: -21.75pt; line-height: normal;">Técnicas de Reiki Occidental<o:p></o:p></li><li style="margin-left: -21.75pt; line-height: normal;">Técnicas de Autopurificación</li><li style="margin-left: -21.75pt; line-height: normal;">Meditación Vipassana<font face="Poppins, serif"><span style="font-size: 10pt;"><o:p></o:p></span></font></li></ul><p class="MsoNormal" style="mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;\r\nmargin-left:-3.75pt;text-indent:-18.0pt;line-height:normal;mso-list:l0 level1 lfo1;\r\ntab-stops:list 36.0pt"><br></p>', 'publicacion-5cfb6f9c89bc6.jpg', 0, '2019-06-08 06:00:00', '2021-11-05 01:33:06', '2019-06-08 06:00:00', 'curso_reiki', 'activo', 3, 0),
	(6, 'Reiki Japonés Nivel 3 Portador de Luz', 'reiki-japones-nivel-3-portador-de-luz', 'El nivel 3 de nuestros cursos de reiki, tendremos el objetivo de buscar un estado mental de estabilidad, uso del símbolo Maestro', '<p class="MsoNormal" style="mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;\r\nline-height:normal">El nivel 3 de nuestros cursos de reiki, tendremos el objetivo de buscar un estado mental de estabilidad, uso del símbolo Maestro<br></p><h5 style="mso-margin-top-alt:auto;mso-margin-bottom-alt:auto;\r\nline-height:normal"> TEMAS</h5><p>\r\n\r\n\r\n\r\n\r\n\r\n</p><ul><li style="line-height: normal;"> Símbolo de Cuarto grado </li><li style="line-height: normal;">Símbolos Antahkarana </li><li style="line-height: normal;">Técnicas de Purificación de cuarto grado </li><li style="line-height: normal;">Oración por la paz Universal </li><li style="line-height: normal;">Afirmaciones </li><li style="line-height: normal;">Técnicas Tradicional de Sanación </li><li style="line-height: normal;">Uso del cuarzo en Reiki </li><li style="line-height: normal;">Parilla\r\nde Cristales de Cuarzo </li><li style="line-height: normal;">Punto Hui Yin y\r\nOrbita Microcosmica </li><li style="line-height: normal;">Cirugía Astral<font face="Poppins, serif"><span style="font-size: 10pt;"><o:p></o:p></span></font></li></ul>', 'publicacion-5cfb7054e6de6.jpg', 0, '2019-06-08 06:00:00', '2021-11-05 01:33:06', '2019-06-08 06:00:00', 'curso_reiki', 'activo', 4, 0),
	(7, 'Reiki Japonés Nivel Maestría Maestro de Luz', 'reiki-japones-nivel-maestria-maestro-de-luz', 'En esta maestría de nuestros cursos de reiki, tendremos el objetivo de profundizar en las prácticas para llegar a ser Maestro de Reiki, aprender los rituales de iniciación', '<p class="MsoNormal">En esta maestría de nuestros cursos de reiki, tendremos el\r\nobjetivo de profundizar en las prácticas para llegar a ser Maestro de Reiki,\r\naprender los rituales de iniciación<o:p></o:p></p><h5><o:p> </o:p>TEMAS</h5><p class="MsoNormal"><o:p></o:p></p><ul><li> Puntos importantes y\r\nperfil del Maestro Reiki<o:p></o:p></li><li>Los cinco principios de Reiki <o:p></o:p></li><li>Linaje  <o:p></o:p></li><li>Revisión de Símbolos <o:p></o:p></li><li>Revisión de Manuales <o:p></o:p></li><li>¿Cómo Sintonizar? <o:p></o:p></li><li>Preparación de Lugar  <o:p></o:p></li><li>Preparación del Maestro <o:p></o:p></li><li>Preparación del Alumno</li><li>Sintonización nivel 1, 2, 3 4 y Maestría<o:p></o:p></li></ul>', 'publicacion-5cfbd6c845cf6.jpg', 0, '2019-06-08 06:00:00', '2021-11-05 01:33:06', '2019-06-08 06:00:00', 'curso_reiki', 'activo', 5, 0),
	(8, 'Cursos de Reiki Tibetano - Tántrico Nivel Practicante y Maestría', 'cursos-de-reiki-tibetano-tantrico-nivel-practicante-y-maestria', 'Una vez realizada la maestría en Reiki Japonés Tradicional se recomienda continuar la formación de cursos de Reiki con el Sistema Tibetano-Tántrico.', '<h5>Introducción</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">Una vez realizada la maestría en Reiki Japonés Tradicional\r\nse recomienda continuar la formación de cursos de Reiki con el Sistema\r\nTibetano-Tántrico.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><p class="MsoNormal">Esta maestría de cursos de reiki toma como base la enseñanza\r\nde Reiki Japonés en los cuatro primeros niveles, enseñando a nivel maestría 11\r\nsímbolos complementarios que permiten llegar a profundidad en la sanación del\r\ncuerpo, mente y energía. Los símbolos tibetanos forman parte del TANTRA, que es\r\nel sistema por el cual purificamos y transformamos, nuestras emociones\r\nconflictos, cuya base es la ignorancia. Con el uso de los símbolos, se\r\ndesarrolla la sabiduría y se nos permite percibir el estado puro del alma. Los\r\nsímbolos tántricos, a diferencia de otros símbolos, se introducen directamente\r\nen los chacras a través del sushumna o canal central, por el chacra corona.\r\nCuando despierta la kundalini, que permanece enroscada en una espiral en forma\r\nde serpiente en la base de la columna, se eleva a través del sushumna para unir\r\nel chacra corona con la divinidad, descrita como la conciencia pura.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><h5>¿A quién van dirigidos los cursos de Reiki\r\nTibetano-Tántrico?</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">A todas las personas que esten interesadas en conocer\r\nsímbolos tántricos-tibetanos para llevar a cabo una sanación más profunda y\r\neficaz. Como requisito de admisión deberá haber cursado Maestría Gokuidaiden\r\nReiki Japonés, firmar reglamento y ser mayor de 13 años o estar acompañado de\r\nun adulto.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><p class="MsoNormal">TEMAS<o:p></o:p></p><ul><li>Meditación de la Maestría de Reiki <o:p></o:p></li><li>Símbolos de la maestría del sistema Tibetano-tantrico <o:p></o:p></li><li>Iniciaciones<o:p></o:p></li><li>Tratamiento de Reiki a nivel Maestría<o:p></o:p></li></ul><p class="MsoNormal"><o:p> </o:p></p><h5>Requisitos</h5><p class="MsoNormal"><o:p></o:p></p><ul><li>Haber cursado cuarto nivel de Reiki Japones<o:p></o:p></li><li>Ser mayor de 13 años<o:p></o:p></li><li>En caso de ser menor de 18 años estar acompañado de un\r\nadulto o firmar carta autorización de Padres o tutor.<o:p></o:p></li><li>Firmar reglamento.<o:p></o:p></li></ul><p class="MsoNormal"><o:p> </o:p></p><h5>Duración</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">28 horas, divididas en 7 clases de 4 horas diarias.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><h5>Todos los cursos de Reiki Tibetano-Tántrico incluyen:</h5><p class="MsoNormal"><o:p></o:p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class="MsoNormal">Manual del curso, CD de música y Meditación del nivel,\r\nConstancia del Nivel<o:p></o:p></p>', 'publicacion-5cfbd907e71f5.jpg', 0, '2019-06-08 06:00:00', '2021-11-05 01:33:06', '2019-06-08 06:00:00', 'curso_reiki', 'activo', 6, 0),
	(9, 'Cursos de Reiki Angélico Nivel Practicante y Maestría', 'cursos-de-reiki-angelico-nivel-practicante-y-maestria', 'Una vez realizada la maestría en Reiki Japonés Tradicional se recomienda continuar la formación de cursos de Reiki con el sistema de Angélico.', '<h5>Introducción</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">Una vez realizada la maestría en Reiki Japonés Tradicional\r\nse recomienda continuar la formación de cursos de Reiki con el sistema de\r\nAngélico.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><p class="MsoNormal">Esta maestría de cursos de Reiki toma como base la enseñanza\r\nde Reiki Japonés en los cuatro primeros niveles. Este curso de reiki tiene como\r\nobjetivo trabajar mano a mano con el Reino Angélico de luz para traer una de\r\nlas formas más elevadas de sanación para individuos, grupos y el planeta. Los\r\nÁngeles son Maestros, los ascendidos del universo, a través de su guía el arte\r\nsanador de Reiki puede actuar en el ser a nivel menta, emocional y físico.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><h5>¿A quién van dirigidos los cursos de Reiki Angélico?</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">A todas las personas que les interese conocer el mundo\r\nAngélico y utilizar símbolos angélicos para llevar a cabo una sanación más\r\nprofunda y eficaz ayudados de los maestros Ascendidos.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><h5>Requisitos</h5><p class="MsoNormal"><o:p></o:p></p><ul><li>Haber cursado cuarto nivel de Reiki Japones<o:p></o:p></li><li>Ser mayor de 13 años<o:p></o:p></li><li>En caso de ser menor de 18 años estar acompañado de un\r\nadulto o firmar carta autorización de Padres o tutor.<o:p></o:p></li><li>Firmar reglamento.<o:p></o:p></li></ul><p class="MsoNormal"><o:p> </o:p></p><h5>TEMAS</h5><p class="MsoNormal"><o:p></o:p></p><ul><li>Quienes son los Ángeles <o:p></o:p></li><li>Invocación a Ángeles <o:p></o:p></li><li>Chacras y Ángeles <o:p></o:p></li><li>Ángeles, colores y peticiones <o:p></o:p></li><li>Sanando como un canal de energía Angélica<o:p></o:p></li><li>Mantras <o:p></o:p></li><li>Símbolos Angélicos<o:p></o:p></li><li>Circulo de sanación<o:p></o:p></li></ul><p class="MsoNormal"><o:p> </o:p></p><h5>Duración</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">28 horas, divididas en 7 clases de 4 horas diarias.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><h5>Todos los cursos de Reiki Angélico incluyen:</h5><p class="MsoNormal"><o:p></o:p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class="MsoNormal">Manual del curso, CD de música y Meditación del nivel,\r\nConstancia del Nivel.<o:p></o:p></p>', 'publicacion-6717bfcbbab23.jpg', 0, '2019-06-08 06:00:00', '2024-10-22 15:07:56', '2019-06-08 06:00:00', 'curso_reiki', 'activo', 7, 0),
	(10, 'Cursos de Reiki Karuna', 'cursos-de-reiki-karuna', 'El sistema Reiki Karuna Prakriti es conocido como la Maestría de Maestrías por el alto nivel vibratorio que se utiliza en los símbolos.', '<h5>Introducción</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">El sistema Reiki Karuna Prakriti es conocido como la\r\nMaestría de Maestrías por el alto nivel vibratorio que se utiliza en los\r\nsímbolos.</p><p class="MsoNormal">El sistema fue desarrollado por William L. Rand en\r\ncolaboración de otros maestros de Reiki y básicamente se trabaja con el “Mara”\r\nque es la parte oscura que podemos llegar a tener y con el uso de los símbolos\r\nKaruna podemos sanar y limpiar.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><h5>Requisitos</h5><p class="MsoNormal"><o:p></o:p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class="MsoNormal">Para poder estudiar este sistema de la compasión es\r\nnecesario tener la maestría de algún otro sistema para poder entender y\r\nasimilar la energía sanadora de sus símbolos, consta de Dos niveles, Practicante\r\ny Maestría: En el primero se enseñan 15 nuevos símbolos y en la Maestría 6 para\r\ngenerar un dominio del Mara. El conocimiento se complementa con Meditaciones de\r\nalta vibración, símbolos anthakarana, Sanación con el Rayo Violeta, y\r\nprotección del Circulo de Fuego azul.<o:p></o:p></p>', 'publicacion-618493c3d1d61.jpg', 0, '2019-06-08 06:00:00', '2021-11-05 02:15:32', '2019-06-08 06:00:00', 'curso_reiki', 'activo', 8, 0),
	(11, 'Cursos de Reiki para niños en verano', 'cursos-de-reiki-para-ninos-en-verano', 'Los niños son el futuro de nuestro planeta y si desde pequeños les damos herramientas que los encaminen a tener una vida con calidad y tranquilidad podemos ayudarlos a ha hacer su mundo mucho mejor.', '<h5>Introducción</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">Los niños son el futuro de nuestro planeta y si desde\r\npequeños les damos herramientas que los encaminen a tener una vida con calidad\r\ny tranquilidad podemos ayudarlos a ha hacer su mundo mucho mejor.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><p class="MsoNormal">Al iniciar a los niños es este sistema energético lo hacemos\r\nde forma didáctica, y amena para que ellos de manera natural adquiera este\r\nconocimiento y aprendan a canalizar la energía de Reiki por su cuerpo y se\r\npuedan ayudar a ellos mismos y a otros. Así como se les enseña el uso que tiene\r\nReiki en la vida cotidiana, como por ejemplo aplicarlo en su comida y en las\r\nmascotas del hogar.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><h5>¿A quién van dirigidos los cursos de Reiki Angélico?</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">El curso está estructurado para que por medio juegos y\r\nanálisis propio de los niños obtengan conocimiento sobre chacras, Energía\r\nUniversal, principios de Reiki, meditación, Mándalas, posiciones de autotratamiento\r\ny tratamiento a otros, uso de cuarzos, todo se hace fomentando la participación\r\nde ellos y generando un trabajo de grupo.<o:p></o:p></p><p class="MsoNormal"><o:p> </o:p></p><h5>Beneficios para los niños</h5><p class="MsoNormal"><o:p></o:p></p><ul><li>Salud física, emocional y mental <o:p></o:p></li><li>Tranquilidad emocional<o:p></o:p></li><li>Control de conductas agresivas<o:p></o:p></li><li>Mayor rendimiento escolar <o:p></o:p></li><li>Conexión con su espiritualidad  <o:p></o:p></li><li>Aumenta el autoestima \r\n<o:p></o:p></li><li>Integración de los niños con la sociedad<o:p></o:p></li></ul><p class="MsoNormal"><o:p> </o:p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class="MsoNormal">Se entrega Manual para el niño, constancia y CD de\r\nmedicación especial para niños.<o:p></o:p></p>', 'publicacion-5cfbdacd8f17d.jpg', 0, '2019-06-08 06:00:00', '2021-11-05 01:33:06', '2019-06-08 06:00:00', 'curso_reiki', 'activo', 10, 0),
	(12, 'Cromoterapia aplicada en Reiki', 'cromoterapia-aplicada-en-reiki', 'En este curso de Reiki se conjuntan la cromoterapia que es una terapia de armonización y colores y el Reiki como un solo método de sanación. Los colores corresponden a vibraciones que tienen velocidades, longitudes y ritmos de ondas diferentes, estos ejercen una influencia física, psíquica y emocional de la cual no somos plenamente conscientes y que permite a nuestra energía vital de tener un estado que facilita la auto sanación.', '<p><span style="color: rgb(51, 51, 51); font-family: " helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;"="">Requisito Indispensable contar con Maestría en el Sistema de Reiki Japonés o Tibetano-Tántrico</span></p><p><span style="color: rgb(51, 51, 51); font-family: " helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;"="">En este curso de Reiki se conjuntan la cromoterapia que es una terapia de armonización y colores y el Reiki como un solo método de sanación. Los colores corresponden a vibraciones que tienen velocidades, longitudes y ritmos de ondas diferentes, estos ejercen una influencia física, psíquica y emocional de la cual no somos plenamente conscientes y que permite a nuestra energía vital de tener un estado que facilita la auto sanación.</span><br></p>', 'publicacion-5cfbdbc6e76c5.jpg', 0, '2019-06-08 06:00:00', '2024-10-08 01:06:12', '2019-06-08 06:00:00', 'curso_reiki', 'inactivo', 11, 0),
	(13, 'Chamanismo aplicado en Reiki', 'chamanismo-aplicado-en-reiki', 'La experiencia Reiki y los conocimientos chámanicos se ven conjugados en este arte de sanación. Combinados ambas disciplinas y utilizando la energía universal y los elementos propios de la madre naturaleza, agua, tierra, fuego y Aire, se desarrolla un tratamiento que equilibre el espíritu y la materia en uno mismo. En el curso de Reiki Chamanico se extraen la energía que no nos pertenece y que influye de manera negativa, con la ayuda del Reiki las transmutamos en luz tanto en el nivel material como en el espiritual.', '<p><span style="color: rgb(51, 51, 51); font-family: " helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" text-align:="" center;"="">Requisito Indispensable contar con Maestría en el Sistema de Reiki Japonés o Tibetano-Tántrico<br></span></p><p><span style="color: rgb(51, 51, 51); font-family: " helvetica="" neue",="" helvetica,="" arial,="" sans-serif;="" font-size:="" 14px;="" text-align:="" center;"="">La experiencia Reiki y los conocimientos chamánicos se ven conjugados en este arte de sanación. Combinados ambas disciplinas y utilizando la energía universal y los elementos propios de la madre naturaleza, agua, tierra, fuego y Aire, se desarrolla un tratamiento que equilibre el espíritu y la materia en uno mismo. En el curso de Reiki Chamánico se extraen la energía que no nos pertenece y que influye de manera negativa, con la ayuda del Reiki las transmutamos en luz tanto en el nivel material como en el espiritual.</span><br></p>', 'publicacion-5cfbdbe98c802.jpg', 0, '2019-06-08 06:00:00', '2024-10-08 01:06:17', '2019-06-08 06:00:00', 'curso_reiki', 'inactivo', 12, 0),
	(15, 'Niños Índigo, Cristal y Arcoiris', 'ninos-indigo-cristal-y-arcoiris', 'Ofrecer información y estrategias efectivas para reconocer y convivir con las personas índigo, cristal y arcoíris, dentro del ambiente familiar y social. Para así lograr una mejor comprensión de la temática de estas nuevas generaciones espirituales', '<p class="MsoNormal"><span style="font-size: 10.5pt; line-height: 107%; font-family: Helvetica, sans-serif; color: rgb(51, 51, 51); background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial;">Ofrecer información y\r\nestrategias efectivas para reconocer y convivir con las personas índigo,\r\ncristal y arcoíris, dentro del ambiente familiar y social. Para así lograr una\r\nmejor comprensión de la temática de estas nuevas generaciones espirituales</span><o:p></o:p></p>', 'publicacion-5cfc553a83cf6.jpg', 0, '2019-06-09 06:00:00', '2025-07-04 00:43:57', '2019-06-09 06:00:00', 'cursos', 'inactivo', 20, 0),
	(16, 'Ángeles: Taller de Luz.', 'angeles-taller-de-luz', 'Ven a conocer el mundo de los ángeles. Estos grandes seres de luz son incansables y muy discretos. Cuando los llamamos descubrimos su fuerza y su apoyo. En esta actividad se realizará meditación y sanación con mantras y símbolos angélicos.', '<p class="MsoNormal">Ven a conocer el mundo de los ángeles. Estos grandes seres\r\nde luz son incansables y muy discretos. Cuando los llamamos descubrimos su\r\nfuerza y su apoyo. En esta actividad se realizará meditación y sanación con\r\nmantras y símbolos angélicos.<o:p></o:p></p>', 'publicacion-5cfc55418824c.jpg', 0, '2019-06-09 06:00:00', '2025-07-04 00:43:57', '2019-06-09 06:00:00', 'cursos', 'inactivo', 18, 0),
	(17, 'Creando mi Mapa de sueños y deseos', 'creando-mi-mapa-de-suenos-y-deseos', 'El mapa de Sueños y Deseos es algo que se debería de realizar todos los años de nuestras vidas, o al menos una vez en nuestra vida. Es una herramienta tan poderosa para conseguir nuestros anhelos que podría decirse que es Mágica.', '<p class="MsoNormal">El mapa de Sueños y Deseos es algo que se debería de\r\nrealizar todos los años de nuestras vidas, o al menos una vez en nuestra vida.\r\nEs una herramienta tan poderosa para conseguir nuestros anhelos que podría\r\ndecirse que es Mágica.<o:p></o:p></p><p class="MsoNormal">Al realizarlo de manera manual  ya que le estamos imprimiendo desde la\r\nconfección nuestra energía y vibración en positivo, debido a las diferentes\r\ntécnicas que realizamos para conectarnos con el universo y vibrar en una\r\nfrecuencia alta y correcta.<o:p></o:p></p><p class="MsoNormal">¿Cuál es el objetivo del mapa? Justamente tener objetivos\r\nclaros, bien elaborados aplicando la "Ley de Atracción" para que nos\r\nguie todos los días recordando los motivos por los cuales nos levantamos para\r\nseguir viviendo, y que esta vida sea plena, y con una dirección. <o:p></o:p></p><p class="MsoNormal">Se realizara una charla sobre la "Ley de\r\nAtracción" que es y como aplicarla en nuestra vida cotidiana.<o:p></o:p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class="MsoNormal">En el mapa a  través\r\nde imágenes, colores, palabras, decretos, afirmaciones, programación y  energía angelical, Reiki nos ayudará a\r\nvisualizar lo que quiero y lo que está por venir.<o:p></o:p></p>', 'publicacion-5cfc5548cc9cb.jpg', 0, '2019-06-09 06:00:00', '2025-07-04 00:43:57', '2019-06-09 06:00:00', 'cursos', 'activo', 14, 0),
	(18, 'Comunicándome con mis Ángeles', 'comunicandome-con-mis-angeles', '¡Establecer una conexión con tus ángeles y guías espirituales es muy emocionante!', '<h5>¡Establecer una conexión con tus ángeles y guías\r\nespirituales es muy emocionante!</h5><p class="MsoNormal"><o:p></o:p></p><p>\r\n\r\n</p><p class="MsoNormal">Conectándonos con el Universo encontraremos una forma\r\namorosa de unirnos con nuestros ángeles guardianes para que nos transmitan sus\r\nenseñanzas, consejos y vivamos días mágicos, con nuevas oportunidades y un\r\nsentimiento profundo de realización con su compañía.<o:p></o:p></p>', 'publicacion-5cfc5f0ecc5f3.jpg', 0, '2019-06-09 06:00:00', '2025-07-04 00:43:57', '2019-06-09 06:00:00', 'cursos', 'inactivo', 21, 0),
	(19, 'En un Mundo de Causas y Consecuencias', 'en-un-mundo-de-causas-y-consecuencias', '“Karma, Dharma y Cerrando Círculos”', '<h5>“Karma, Dharma y Cerrando Círculos”</h5><p class="MsoNormal"><o:p></o:p></p><p>\r\n\r\n</p><p class="MsoNormal">Cuando reflexionamos en algo aprendemos de ello. Cuando\r\nhacemos ciertas cosas no lo vemos tan mal como cuando nos las hacen. Por eso\r\ndecimos que la Ley del Karma es el fundamento de esta escuela y de todo el\r\naprendizaje. Reflexionar en lo que se nos devuelve por nuestras acciones hará\r\nque comprendamos finalmente. Revisando la teoría y realizando actividades de\r\nCierre de Círculos y depuramiento Kármico, nos ayudaremos a saldar todo el bien\r\nse ha hecho y enmendar todo el mal que hemos realizado. Preparándonos para un\r\ncambio en nuestra vida.<o:p></o:p></p>', 'publicacion-5cfc602a09a3f.jpg', 0, '2019-06-09 06:00:00', '2025-07-04 00:43:57', '2019-06-09 06:00:00', 'cursos', 'inactivo', 22, 0),
	(20, 'Taller: Reiki y Abundancia', 'taller-reiki-y-abundancia', 'Nos adentraremos en lo más profundo de tus creencias acerca de la abundancia, en una evocación al Universo, en este taller se te enseñaran dos planes hacia la abundancia con un programa para aplicar en 21 días cada uno que te conducirá a explorar los paradigmas que te impiden experimentar todo lo que deseas y necesitas en la vida. Cambiando programaciones erróneas de escases que tenemos en nuestro ser y empezar a vivir en abundancia, por medio de dichos programas liberándonos de bloqueos y dependencias emocionales.', '<p style="margin-right: 0px; margin-bottom: 10px; margin-left: 0px; color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Nos adentraremos en lo más profundo de tus creencias acerca de la abundancia, en una evocación al Universo, en este taller se te enseñaran dos planes hacia la abundancia con un programa para aplicar en 21 días cada uno que te conducirá a explorar los paradigmas que te impiden experimentar todo lo que deseas y necesitas en la vida. Cambiando programaciones erróneas de escases que tenemos en nuestro ser y empezar a vivir en abundancia, por medio de dichos programas liberándonos de bloqueos y dependencias emocionales.</p><p style="margin-right: 0px; margin-bottom: 10px; margin-left: 0px; color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Identificaremos las creencias que nos limitan sanándolas o reprogramando y abriremos la puerta a la abundancia en nuestra vida. Necesitamos volcarnos hacia adentro para lograr la sanación.</p><p style="margin-right: 0px; margin-bottom: 10px; margin-left: 0px; color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Se darán tips para además mover la energía de abundancia en nuestra casa, negocio, y oficina.  </p>', 'publicacion-5cfc604fa9124.jpg', 0, '2019-06-09 06:00:00', '2025-07-04 00:43:57', '2019-06-09 06:00:00', 'cursos', 'inactivo', 23, 0),
	(21, 'Uso de péndulo', 'uso-de-pendulo', 'Los asistentes a este taller conocerán los antecedentes del Péndulo, cómo prepararlo y cuáles son las reglas básicas para su uso. De esta manera podemos aplicarlo en diferentes áreas nuestra vida para nuestro bienestar en salud, energía, y el hogar, se enseñara el uso del Péndulo para armonizar el aura y los chacras, armonizar tu hogar y tener respuestas a preguntas que tenemos sobre diferentes temas. Con sencillos ejercicios, podremos conocer las maravillas que nos ofrece esta sencilla herramienta.', '<p class="MsoNormal">Los asistentes a este taller conocerán los antecedentes del\r\nPéndulo, cómo prepararlo y cuáles son las reglas básicas para su uso. De esta\r\nmanera podemos aplicarlo en diferentes áreas nuestra vida para nuestro\r\nbienestar en salud, energía, y el hogar, se enseñara el uso del Péndulo para\r\narmonizar el aura y los chacras, armonizar tu hogar y tener respuestas a\r\npreguntas que tenemos sobre diferentes temas. Con sencillos ejercicios,\r\npodremos conocer las maravillas que nos ofrece esta sencilla herramienta.<o:p></o:p></p>', 'publicacion-5cfc607ea7db2.jpg', 0, '2019-06-09 06:00:00', '2025-08-21 19:57:06', '2019-06-09 06:00:00', 'cursos', 'inactivo', 16, 0),
	(22, 'Ya tenemos Angelorama 2025.                 Agenda tu cita tendremos Presencial y On-Line', 'ya-tenemos-angelorama-2025-agenda-tu-cita-tendremos-presencial-y-on-line', 'Existen Ángeles y Arcángeles que en este momento están susurrándote palabras amorosas y precisas que sirven de guía y ayuda en cada área de tu vida y con el ÁNGELORAMA podemos tener estos mensajes para cada mes del año.', '<!--[if gte mso 9]><xml>\r\n <o:OfficeDocumentSettings>\r\n  <o:AllowPNG></o:AllowPNG>\r\n </o:OfficeDocumentSettings>\r\n</xml><![endif]--><!--[if gte mso 9]><xml>\r\n <w:WordDocument>\r\n  <w:View>Normal</w:View>\r\n  <w:Zoom>0</w:Zoom>\r\n  <w:TrackMoves></w:TrackMoves>\r\n  <w:TrackFormatting></w:TrackFormatting>\r\n  <w:HyphenationZone>21</w:HyphenationZone>\r\n  <w:PunctuationKerning></w:PunctuationKerning>\r\n  <w:ValidateAgainstSchemas></w:ValidateAgainstSchemas>\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\r\n  <w:IgnoreMixedContent>false</w:IgnoreMixedContent>\r\n  <w:AlwaysShowPlaceholderText>false</w:AlwaysShowPlaceholderText>\r\n  <w:DoNotPromoteQF></w:DoNotPromoteQF>\r\n  <w:LidThemeOther>ES-MX</w:LidThemeOther>\r\n  <w:LidThemeAsian>X-NONE</w:LidThemeAsian>\r\n  <w:LidThemeComplexScript>X-NONE</w:LidThemeComplexScript>\r\n  <w:Compatibility>\r\n   <w:BreakWrappedTables></w:BreakWrappedTables>\r\n   <w:SnapToGridInCell></w:SnapToGridInCell>\r\n   <w:WrapTextWithPunct></w:WrapTextWithPunct>\r\n   <w:UseAsianBreakRules></w:UseAsianBreakRules>\r\n   <w:DontGrowAutofit></w:DontGrowAutofit>\r\n   <w:SplitPgBreakAndParaMark></w:SplitPgBreakAndParaMark>\r\n   <w:EnableOpenTypeKerning></w:EnableOpenTypeKerning>\r\n   <w:DontFlipMirrorIndents></w:DontFlipMirrorIndents>\r\n   <w:OverrideTableStyleHps></w:OverrideTableStyleHps>\r\n  </w:Compatibility>\r\n  <m:mathPr>\r\n   <m:mathFont m:val="Cambria Math"></m:mathFont>\r\n   <m:brkBin m:val="before"></m:brkBin>\r\n   <m:brkBinSub m:val="--"></m:brkBinSub>\r\n   <m:smallFrac m:val="off"></m:smallFrac>\r\n   <m:dispD