nltr;unicode-bidi:embed;mso-line-break-override:none;word-break:normal;\r\npunctuation-wrap:hanging"><br><!--[endif]--></div><div style="language:es-MX;margin-top:0pt;margin-bottom:0pt;margin-left:.19in;\r\ntext-indent:-.19in;text-align:justify;text-justify:inter-ideograph;direction:\r\nltr;unicode-bidi:embed;mso-line-break-override:none;word-break:normal;\r\npunctuation-wrap:hanging"><span style="font-size:11.0pt"><span style="mso-special-format:bullet;font-family:Arial">•</span></span><span style="font-size:11.0pt;font-family:Classica;mso-ascii-font-family:Classica;\r\nmso-fareast-font-family:+mn-ea;mso-bidi-font-family:+mn-cs;mso-fareast-theme-font:\r\nminor-fareast;mso-bidi-theme-font:minor-bidi;color:#493B5B;mso-font-kerning:\r\n12.0pt;language:es-MX;font-weight:bold;mso-style-textfill-type:solid;\r\nmso-style-textfill-fill-color:#493B5B;mso-style-textfill-fill-alpha:100.0%">No\r\nnecesitas experiencia</span><span style="font-size:11.0pt;font-family:Classica;\r\nmso-ascii-font-family:Classica;mso-fareast-font-family:+mn-ea;mso-bidi-font-family:\r\n+mn-cs;mso-fareast-theme-font:minor-fareast;mso-bidi-theme-font:minor-bidi;\r\ncolor:#493B5B;mso-font-kerning:12.0pt;language:es-MX;mso-style-textfill-type:\r\nsolid;mso-style-textfill-fill-color:#493B5B;mso-style-textfill-fill-alpha:100.0%">,\r\nsólo la voluntad de mirar hacia adentro.</span></div><div style="language:es-MX;margin-top:0pt;margin-bottom:0pt;margin-left:.19in;\r\ntext-indent:-.19in;text-align:justify;text-justify:inter-ideograph;direction:\r\nltr;unicode-bidi:embed;mso-line-break-override:none;word-break:normal;\r\npunctuation-wrap:hanging"><br><!--[endif]--></div><div style="language:es-MX;margin-top:0pt;margin-bottom:0pt;margin-left:.19in;\r\ntext-indent:-.19in;text-align:justify;text-justify:inter-ideograph;direction:\r\nltr;unicode-bidi:embed;mso-line-break-override:none;word-break:normal;\r\npunctuation-wrap:hanging"><span style="font-size:11.0pt"><span style="mso-special-format:bullet;font-family:Arial">•</span></span><span style="font-size:11.0pt;font-family:Classica;mso-ascii-font-family:Classica;\r\nmso-fareast-font-family:+mn-ea;mso-bidi-font-family:+mn-cs;mso-fareast-theme-font:\r\nminor-fareast;mso-bidi-theme-font:minor-bidi;color:#493B5B;mso-font-kerning:\r\n12.0pt;language:es-MX;font-weight:bold;mso-style-textfill-type:solid;\r\nmso-style-textfill-fill-color:#493B5B;mso-style-textfill-fill-alpha:100.0%">Acompaña\r\na otros desde la empatía</span><span style="font-size:11.0pt;font-family:Classica;\r\nmso-ascii-font-family:Classica;mso-fareast-font-family:+mn-ea;mso-bidi-font-family:\r\n+mn-cs;mso-fareast-theme-font:minor-fareast;mso-bidi-theme-font:minor-bidi;\r\ncolor:#493B5B;mso-font-kerning:12.0pt;language:es-MX;mso-style-textfill-type:\r\nsolid;mso-style-textfill-fill-color:#493B5B;mso-style-textfill-fill-alpha:100.0%">,\r\nno desde la predicción.</span></div><div style="language:es-MX;margin-top:0pt;margin-bottom:0pt;margin-left:.19in;\r\ntext-indent:-.19in;text-align:justify;text-justify:inter-ideograph;direction:\r\nltr;unicode-bidi:embed;mso-line-break-override:none;word-break:normal;\r\npunctuation-wrap:hanging"><br><!--[endif]--></div><div style="language:es-MX;margin-top:0pt;margin-bottom:0pt;margin-left:.19in;\r\ntext-indent:-.19in;text-align:justify;text-justify:inter-ideograph;direction:\r\nltr;unicode-bidi:embed;mso-line-break-override:none;word-break:normal;\r\npunctuation-wrap:hanging"><span style="font-size:11.0pt"><span style="mso-special-format:bullet;font-family:Arial">•</span></span><span style="font-size:11.0pt;font-family:Classica;mso-ascii-font-family:Classica;\r\nmso-fareast-font-family:+mn-ea;mso-bidi-font-family:+mn-cs;mso-fareast-theme-font:\r\nminor-fareast;mso-bidi-theme-font:minor-bidi;color:#493B5B;mso-font-kerning:\r\n12.0pt;language:es-MX;font-weight:bold;mso-style-textfill-type:solid;\r\nmso-style-textfill-fill-color:#493B5B;mso-style-textfill-fill-alpha:100.0%">Enfoque\r\nterapéutico </span><span style="font-size:11.0pt;font-family:Classica;\r\nmso-ascii-font-family:Classica;mso-fareast-font-family:+mn-ea;mso-bidi-font-family:\r\n+mn-cs;mso-fareast-theme-font:minor-fareast;mso-bidi-theme-font:minor-bidi;\r\ncolor:#493B5B;mso-font-kerning:12.0pt;language:es-MX;mso-style-textfill-type:\r\nsolid;mso-style-textfill-fill-color:#493B5B;mso-style-textfill-fill-alpha:100.0%">basado\r\nen psicología simbólica, intuición, ética y práctica vivencial.</span></div><div style="language:es-MX;margin-top:0pt;margin-bottom:0pt;margin-left:.19in;\r\ntext-indent:-.19in;text-align:justify;text-justify:inter-ideograph;direction:\r\nltr;unicode-bidi:embed;mso-line-break-override:none;word-break:normal;\r\npunctuation-wrap:hanging"><br><!--[endif]--></div><p style="language:es-MX;margin-top:0pt;margin-bottom:0pt;margin-left:0in;\r\ntext-align:justify;text-justify:inter-ideograph;direction:ltr;unicode-bidi:\r\nembed;mso-line-break-override:none;word-break:normal;punctuation-wrap:hanging">\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><div style="language:es-MX;margin-top:0pt;margin-bottom:0pt;margin-left:.19in;\r\ntext-indent:-.19in;text-align:justify;text-justify:inter-ideograph;direction:\r\nltr;unicode-bidi:embed;mso-line-break-override:none;word-break:normal;\r\npunctuation-wrap:hanging"><span style="font-size:11.0pt"><span style="mso-special-format:bullet;font-family:Arial">•</span></span><span style="font-size:11.0pt;font-family:Classica;mso-ascii-font-family:Classica;\r\nmso-fareast-font-family:+mn-ea;mso-bidi-font-family:+mn-cs;mso-fareast-theme-font:\r\nminor-fareast;mso-bidi-theme-font:minor-bidi;color:#493B5B;mso-font-kerning:\r\n12.0pt;language:es-MX;font-weight:bold;mso-style-textfill-type:solid;\r\nmso-style-textfill-fill-color:#493B5B;mso-style-textfill-fill-alpha:100.0%">Respeto\r\ncon el alma y el proceso del consultante.</span></div>', 'publicacion-61848132521ba.jpg', 0, '2019-06-09 06:00:00', '2026-04-04 22:01:14', '2019-06-09 06:00:00', 'cursos', 'inactivo', 2, 1),
	(27, 'Barras de Access', 'barras-de-access', 'Comienza a crear tu vida con Facilidad, Gozo y Gloria', '<p class="MsoNormal">Comienza a crear tu vida con Facilidad, Gozo y Gloria<o:p></o:p></p><p class="MsoNormal">Las BARRAS DE ACCESS son una técnica de aplicación manual\r\nque, mediante unos suaves toques en puntos específicos de la cabeza, induce un\r\ncambio en las ondas cerebrales y elimina el exceso de carga electromagnética de\r\nlos mismos. En una sesión de BARRAS el cerebro del paciente pasa de ondas Beta,\r\npropias del estado de vigilia, a ondas Theta o Delta, que se alcanzan solo en\r\nestados de relajación profunda.<o:p></o:p></p><p class="MsoNormal">Los puntos que se activan durante la sesión de BARRAS DE\r\nACCESS son 32 Barras energéticas situadas en la cabeza. Cada una de estas\r\nBARRAS contiene información sobre determinadas áreas de la vida: dinero,\r\ncontrol, creatividad, poder, sexualidad, cuerpo, envejecimiento, alegría,\r\ntristeza, etc. Esta información son los puntos de vista que hemos ido creando y\r\nhaciendo significativos a través de los años y que, de una forma u otra, nos\r\nmantienen anclados y nos impiden mejorar, porque están limitando nuestra\r\ncapacidad de recibir mucho más de esta vida.<o:p></o:p></p><p class="MsoNormal">Al ser estimuladas, las BARRAS comienzan a descargarse y a\r\neliminar estas informaciones. Recibir sesiones de BARRAS es como “formatear”\r\nnuestro cerebro, del mismo modo que haríamos con el disco duro de nuestra\r\ncomputadora.<o:p></o:p></p><p class="MsoNormal">Beneficios:<o:p></o:p></p><p class="MsoNormal">Elimina el parloteo mental<o:p></o:p></p><p class="MsoNormal">Brinda una relajación profunda.<o:p></o:p></p><p class="MsoNormal">Coayuda en casos de Estrés, Ansiedad y Depresión<o:p></o:p></p><p class="MsoNormal">Alivia la ansiedad en mujeres Embarazadas<o:p></o:p></p><p class="MsoNormal">Brinda confianza en niños y adolescentes antes de los\r\nexámenes: da mayor concentración<o:p></o:p></p><p class="MsoNormal">Combate y previene el Insomnio<o:p></o:p></p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class="MsoNormal">Ayuda a personas con TDA<o:p></o:p></p>', 'publicacion-617ac42f9c824.jpg', 0, '2019-06-09 06:00:00', '2026-04-04 22:41:05', '2019-06-09 06:00:00', 'terapia', 'activo', 0, 1),
	(28, 'Reiki Japonés', 'reiki-japones', 'Una sesión de Reiki puede durar aproximadamente cuarenta y cinco minutos y el paciente permanecerá acostado en una camilla, descalzo y vestido. Durante la sesión se utiliza música suave y aromas como incienso o esencias (aromaterapia).', '<p class="MsoNormal">Cómo es una sesión de Reiki</p><p class="MsoNormal">Una sesión de Reiki puede durar aproximadamente cuarenta y\r\ncinco minutos y el paciente permanecerá acostado en una camilla, descalzo y\r\nvestido. Durante la sesión se utiliza música suave y aromas como incienso o\r\nesencias (aromaterapia).</p><p class="MsoNormal">Se colocan las manos en ciertas posiciones en el cuerpo\r\nllamados chacras y a en puntos desde donde fluye la energia a todo el cuerpo.</p><p class="MsoNormal">Durante un tratamiento, se siente una relajación profunda,\r\nuna gran sensación de paz. Muchas personas se quedan dormidas, cosa que no\r\ninfluye para nada en el resultado final, algunas siente un cosquilleo, calor o\r\nfrío en diferentes partes del cuerpo según fluye la energía, otras personas ven\r\ncolores, experimentan una sensación de "flotar" o sienten emociones\r\nque salen a la superficie y otras no sienten nada y no por ello el Reiki no\r\nestá funcionando.</p><p class="MsoNormal">Buscando el terapeuta ser un canal de Energía puro para\r\nalimentar el cuerpo de energía positiva y de esta forma lograr la sanación o\r\ntranquilidad-</p><p class="MsoNormal">¿Cuáles son los primeros resultados de un tratamiento Reiki\r\n?</p><p class="MsoNormal">A nivel físico: Mayor energización y mejoría en el\r\nfuncionamiento corporal.</p><p class="MsoNormal">A nivel emocional: Propicia un estado de calma, aceptación\r\nde los sentimientos, apertura a dar y recibir amor, conciencia de autoestima.\r\nCreatividad integral desapareciendo miedos, complejos y culpas.</p><p class="MsoNormal">A nivel mental: Armonía, deseo profundo de salud y\r\nbienestar, equilibrio en las relaciones humanas, claridad de pensamiento,\r\nbúsqueda de sentido en la vida. Autoconfianza, flexibilidad ante la vida,\r\nclaridad y concentración.</p><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class="MsoNormal">A nivel espiritual: Orienta hacia el bien propio y el\r\ncolectivo, abre a la inspiración superior, propicia a separarse de costumbres\r\nnocivas y oscuras. Fuerza interior.<o:p></o:p></p>', 'publicacion-671458178746e.jpg', 0, '2019-06-09 06:00:00', '2024-10-20 01:08:39', '2019-06-09 06:00:00', 'terapia', 'activo', 1, 0),
	(29, 'Limpias para la abundancia y depuradoras.', 'limpias-para-la-abundancia-y-depuradoras', 'Empieza bien el año 2015, prepárate para que te rinda tu dinero y desaloja toda carga negativa que recibiste a lo largo del año.. Importante solicitar cita para que se les indique las hierbas o material que deben traer.', '<p><span style="color: rgb(51, 51, 51); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 14px;">Empieza bien el año 2015, prepárate para que te rinda tu dinero y desaloja toda carga negativa que recibiste a lo largo del año.. Importante solicitar cita para que se les indique las hierbas o material que deben traer.</span><br></p>', 'publicacion-5cfc65a1561f7.jpg', 0, '2019-06-09 06:00:00', '2023-06-19 19:23:36', '2019-06-09 06:00:00', 'terapia', 'inactivo', 4, 0),
	(30, 'ThetaHealing', 'thetahealing', 'Esta técnica es una herramienta que nos da el poder y la habilidad para quitar, sacar, y reemplazar sentimientos, programas, creencias y pensamientos que nos influencian negativamente, sustituyéndolos o cambiándolos por pensamientos, sentimientos, programas y creencias positivas. Esto es de lo más poderoso, rápido y eficiente que tiene la técnica.', '<p><span style="color: rgb(51, 51, 51); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 14px;">Esta técnica es una herramienta que nos da el poder y la habilidad para quitar, sacar, y reemplazar sentimientos, programas, creencias y pensamientos que nos influencian negativamente, sustituyéndolos o cambiándolos por pensamientos, sentimientos, programas y creencias positivas. Esto es de lo más poderoso, rápido y eficiente que tiene la técnica.</span><br></p>', 'publicacion-5cfc65b61f87d.jpg', 0, '2019-06-09 06:00:00', '2019-06-10 17:12:15', '2019-06-09 06:00:00', 'terapia', 'activo', 5, 0),
	(31, 'Lectura de Oráculo de Ángeles', 'lectura-de-oraculo-de-angeles', 'Esta es una herramienta de sanación espiritual, que implica trabajar con los Arcángeles y Ángeles para armonizar aspectos de nuestra vida. Se canalizan o se recibe el mensaje que ellos quieren darte para tu vida. Además el consultante realiza preguntas y son contestadas por el oráculo de los ángeles.', '<p><span style="color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Esta es una herramienta de sanación espiritual, que implica trabajar con los Arcángeles y Ángeles para armonizar aspectos de nuestra vida. Se canalizan o se recibe el mensaje que ellos quieren darte para tu vida. Además el consultante realiza preguntas y son contestadas por el oráculo de los ángeles.</span><br></p>', 'publicacion-6185df508865f.jpg', 0, '2019-06-09 06:00:00', '2021-11-06 01:50:08', '2019-06-09 06:00:00', 'terapia', 'activo', 6, 0),
	(32, 'Cirugías Áuricas y Astrales', 'cirugias-auricas-y-astrales', 'Nuestro campo energético al igual que nuestras emociones o nuestro cuerpo físico, puede tener fisuras, cortes y fugas energéticas; es por eso que el "cosido" del aura es tan importante como la limpieza. Es por esas grietas por donde se nos escapa la energía vital, la que necesitamos para enfrentarnos a nuestro día a día.', '<p><span style="color: rgb(51, 51, 51); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 14px;">Nuestro campo energético al igual que nuestras emociones o nuestro cuerpo físico, puede tener fisuras, cortes y fugas energéticas; es por eso que el "cosido" del aura es tan importante como la limpieza. Es por esas grietas por donde se nos escapa la energía vital, la que necesitamos para enfrentarnos a nuestro día a día.</span><br></p>', 'publicacion-5cfc6611370b2.jpg', 0, '2019-06-09 06:00:00', '2023-06-19 19:24:22', '2019-06-09 06:00:00', 'terapia', 'inactivo', 7, 0),
	(33, 'Limpias Energéticas', 'limpias-energeticas', 'Las limpias Energéticas se usan para liberar a la persona de todas las vibraciones y energía negativas etc. En el Barrido Energético se desbloquean todos los puntos energéticos del cuerpo, con el uso de veladoras, aromas, flores, baños con elementos naturales. Esto permite que la Energía Universal fluya por el cuerpo entero manteniendo la conexión entre la Mente, el Cuerpo y el Espíritu, manteniendo a la persona perfectamente balanceada y equilibrada.', '<p>Las limpias Energéticas se usan para liberar a la persona de todas las vibraciones y energía negativas etc. En el Barrido Energético se desbloquean todos los puntos energéticos del cuerpo, con el uso de veladoras, aromas, flores, baños con elementos naturales. Esto permite que la Energía Universal fluya por el cuerpo entero manteniendo la conexión entre la Mente, el Cuerpo y el Espíritu, manteniendo a la persona perfectamente balanceada y equilibrada.<br></p>', 'publicacion-5cfc66bdd3c81.jpg', 0, '2019-06-09 06:00:00', '2023-06-19 19:23:46', '2019-06-09 06:00:00', 'terapia', 'inactivo', 8, 0),
	(34, 'Angeloterapia', 'angeloterapia', 'Esta es una herramienta de sanación espiritual, que implica trabajar con los Arcángeles y Ángeles para armonizar aspectos de nuestra vida. Utilizando frases positivas que nos permitan, incorporar el AMOR a nuestra vida.', '<p>Esta es una herramienta de sanación espiritual, que implica trabajar con los Arcángeles y Ángeles para armonizar aspectos de nuestra vida. Utilizando frases positivas que nos permitan, incorporar el AMOR a nuestra vida.</p><p><br></p><p>Una sesión de Angeloterapia consiste en 4 fases:</p><p><br></p><p>-Mensaje de los Arcángeles: En esta parte se canaliza o se recibe el mensaje que ellos quieren darte para tu vida.</p><p><br></p><p>-Escaneo del sistema energético, con la ayuda de los ángeles se realiza un escaneo para ver en qué áreas hay que realizar trabajo en nuestra vida diaria. Algunas veces se reciben algunos consejos de ellos.</p><p><br></p><p>-Sanación con Arcángeles: Ellos son los guías de la sanación</p><p><br></p><p>- Preguntas y respuestas: En esta sección el consultante realiza preguntas y son contestadas por el oráculo de los ángeles.</p>', 'publicacion-671454ae76197.jpg', 0, '2019-06-09 06:00:00', '2024-10-20 00:54:06', '2019-06-09 06:00:00', 'terapia', 'activo', 9, 0),
	(35, 'Flores de Bach', 'flores-de-bach', 'Son una serie de esencias naturales utilizadas para tratar diversas situaciones emocionales, como miedos, soledad, desesperación, estrés, obsesiones y menopausia.Las flores contienen una energía poderosa que combina la fuerza del sol, la pureza de la tierra y la energía vital del agua y el viento. Usar las flores para curarnos no es algo nuevo, pero el Doctor Bach, médico británico, descubrió en la sutil energía de las flores un poder curativo poderoso.\r\n\r\n', '<p>Son una serie de esencias naturales utilizadas para tratar diversas situaciones emocionales, como miedos, soledad, desesperación, estrés, obsesiones y menopausia.Las flores contienen una energía poderosa que combina la fuerza del sol, la pureza de la tierra y la energía vital del agua y el viento. Usar las flores para curarnos no es algo nuevo, pero el Doctor Bach, médico británico, descubrió en la sutil energía de las flores un poder curativo poderoso.</p><p>El Dr. Bach estaba convencido que la salud era el fruto de un equilibrio y armonía emocional. El afirmaba que todo ser viviente provenía de una energía vibrante a la cual llamaba Chispa divina o Amor, una fuente de vida presente en cada ser humano que se podía e podía manifestar tanto en su mente como en su cuerpo cuya principal manifestación era la salud.</p><p>Además, Bach decía que, y que el alma de cada ser vivo venía a cumplir una misión específica que es igual de importante en cada uno. Cuando esta misión Divina es interrumpida o bloqueada por los impulsos de la personalidad se presentará un conflicto y desequilibrio en el flujo d esta divinidad dentro de uno, la cual se evidenciará en un bloqueo en el flujo de nuestra energía vital y se manifestará como un síntoma emocional conflictivo, el cual, si este se prolonga, proporcionará como resultado manifestaciones físicas las cuales conocemos como enfermedades.</p><p>Así pues, El Dr. Bach resumía su filosofía en el cumplimiento de una misión del alma en la vida, la cual, de no ser llevada a cabo, se sufriría de desequilibrios y emociones inestables y conflictivas las cuales pronto llevarían a la persona a padecer debilidades, afecciones y trastornos corporales.</p><p>Todo esto se podría resumir en unas cuantas palabras: si el ser humano no se realiza en su verdadera  felicidad, entonces, enfermará.</p><p>Tratar de curar alguna afección sin comprender la profundidad de las raíces que la generan, sólo corregirá temporalmente la afección.</p><p>El Dr. Bach consideraba dos equivocaciones primordiales para interrumpir el flujo natural de la salud:</p><p>1. La separación de la misión de vida con la personalidad.</p><p>2. La crueldad o el mal hacia los demás (la cual deriva de la ignorancia y de la falta de comprensión y autoconocimiento).</p><p>En su importante labor en la salud, Bach llegó a concluir que el organismo decaía, debilitaba y se enfermaba como consecuencia principalmente a las siguientes formas de comportamiento o reacción ante la vida:</p><p>IGNORANCIA: la cual conduce al miedo, al temor, al orgullo, a la falta de paz y claridad y hacia todas aquellas conductas destructivas.</p><p>ORGULLO: sentirse más que alguna otra persona o ser.</p><p>INESTABILIDAD E INSEGURIDAD: un comportamiento decidioso y poco constante, el cual deriva de la falta de confianza en uno mismo y en la falta de reconocimiento de un orden universal perfecto y armónico.</p><p>EGOÍSMO: el cual consiste en sólo tomar en cuenta el punto de vista propio y las necesidades propias, dejando a un lado y no considerando a los demás. El egoísmo es resultado también de la ignorancia y de la falta de comprensión y autoconocimiento.</p><p>CRUELDAD: lastimar o dañar a los demás o a ti mismo. La cueldad es consecuencia de una falta de reconocimiento del amor dentro de uno mismo y del otro ser humano o ser viviente.</p><p>ODIO: es la ausencia de amor o conocimiento.</p><p>Todas estas emociones y actitudes ante la vida llevan a la persona a bloquear su flujo de energía, todas ellas, de alguna forma, provocan una severa resistencia en el cuerpo, la cual desgasta con el tiempo al organismo.</p><p>Para menguar los efectos de estas mociones y dar una alternativa útil y natural al ser humano para ayudarlo a estar más en paz mientras aprende de sus comportamientos, el Dr. Bach ideo lo que ahora conocemos como esencias florales, las cuales tienen la misión de ayudar a elevar la vibración energética en la persona, ayudando a acercarla a su propia esencia interior para que pueda retomar su orientación primordial en la vida.</p><p>Las Flores de Bach ayudan a tener una mejor disposición en nuestra consciencia de las experiencias y el aprendizaje que hay en ellas, además de que ayudan a desarrollar una mejor comprensión para evitar el sufrimiento y, por ende, la enfermedad en todos sus niveles.</p><p>La enfermedad es, por esencia, el fruto del conflicto</p><p>Esencias Florales de Bach</p><p>Las flores de Bach son una de las alternativas de la medicina integral la cual consiste en una serie de esencias naturales utilizadas para tratar distintas reacciones emotivas como el miedo, la inseguridad, la desesperación, las depresión, el estrés, la ansiedad, etc.</p><p>Se descubrieron entre los años 1926 y 1934 por el doctor británico Edward Bach, un gran investigador que era, además, médico y homeópata. Observó a diversas flores silvestres nativas de la región de Gales, en Gran Bretaña. Sus experimentos lo llevaron a encontrar 38 remedios o elixires naturales cada uno con propiedades curativas para curar diversos conflictos emocionales. A estas 38 flores se les llaman Flores de Bach.</p><p>El desarrolló lo que ahora se conoce como la Terapia de las emociones, la cual, cuando es llevada por un terapeuta profesional, puede dar excelentes resultados ayudando a sanar las emociones y, por ende, el cuerpo.</p><p>Las flores de Bach han sido de gran ayuda en el tratamiento de:</p><p>Afecciones mentales y emocionales: como inseguridad, miedo, obsesiones, inestabilidad, inseguridad, depresión, etc.</p><p>En adolescentes y niños: en épocas de cambios, de estrés fuerte, de inseguridad, aislamiento, etc.</p><p>En mujeres durante el embarazo, el parto, la lactancia y la menopausia.</p><p>En bebés: desde que está recién nacido se le puede empezar a administrar las flores de Bach, las cuales son totalmente inofensivas y le ayudaran al bebe a bajar su estrés, a equilibrar su energía y armonizarlo interiormente.</p><p>En animales: también los animales pueden hacer uso de las flores de Bach debido a que ellos también experimentan emociones y responden a cambios y situaciones estresantes como nuevos ambientes, cambio de dueño, etc.</p><p>Uso en plantas: podemos observar las emociones en el reino vegetal cuando vemos las plantas: si están verdes, fuertes, sin plaga, etc. Cuando no están así, podemos ver a las plantas tristes, decaídas, depresivas, enfermas, etc. Las flores de Bach pueden ayudar a las plantas a equilibra su energía y ayudarles a enfrentar situaciones estresantes.</p><p>La flores de Bach no tienen efectos secundarios y pueden tomase alternativamente con otros tratamientos naturales.</p>', 'publicacion-5cfc6728a476c.jpg', 0, '2019-06-09 06:00:00', '2019-06-10 17:12:08', '2019-06-09 06:00:00', 'terapia', 'activo', 10, 0),
	(36, 'Reiki Chamánico', 'reiki-chamanico', 'La experiencia Reiki y los conocimientos chamánicos se ven conjugados en este arte de sanación. Combinando ambas disciplinas y utilizando la energía universal y los elementos propios de la madre naturaleza, agua, tierra, fuego y aire; Se desarrolla un tratamiento que equilibre el espíritu y la materia en uno mismo. En el Reiki Chamánico se extraen la energía que no nos pertenece y que influye de manera negativa, la con ayuda del Reiki las transmutamos en luz tanto en el nivel material como en el espiritual.', '<p><span style="color: rgb(51, 51, 51); font-family: &quot;Helvetica Neue&quot;, Helvetica, Arial, sans-serif; font-size: 14px;">La experiencia Reiki y los conocimientos chamánicos se ven conjugados en este arte de sanación. Combinando ambas disciplinas y utilizando la energía universal y los elementos propios de la madre naturaleza, agua, tierra, fuego y aire; Se desarrolla un tratamiento que equilibre el espíritu y la materia en uno mismo. En el Reiki Chamánico se extraen la energía que no nos pertenece y que influye de manera negativa, la con ayuda del Reiki las transmutamos en luz tanto en el nivel material como en el espiritual.</span><br></p>', 'publicacion-5cfc673e0cbd4.jpg', 0, '2019-06-09 06:00:00', '2024-10-08 01:05:08', '2019-06-09 06:00:00', 'terapia', 'inactivo', 11, 0),
	(37, 'Reiki con Cromoterapia', 'reiki-con-cromoterapia', 'Se conjugan la cromoterapia, que es una terapia de armonización y de ayuda a la curación natural por medio de los colores, y el Reiki como un solo método de sanación. Los colores corresponden a vibraciones que tienen velocidades, longitudes y ritmos de ondas diferentes, estos ejercen una influencia física, psíquica y emocional de la cual no somos plenamente conscientes y que permite a nuestra energía vital de tener un estado que facilita la autosanación.', '<p><span style="color: rgb(51, 51, 51); font-family: arial, sans-serif; font-size: 13.3333px;">Se conjugan la cromoterapia, que es una terapia de armonización y de ayuda a la curación natural por medio de los colores, y el Reiki como un solo método de sanación. Los colores corresponden a vibraciones que tienen velocidades, longitudes y ritmos de ondas diferentes, estos ejercen una influencia física, psíquica y emocional de la cual no somos plenamente conscientes y que permite a nuestra energía vital de tener un estado que facilita la autosanación.</span><br></p>', 'publicacion-5cfc67528d172.jpg', 0, '2019-06-09 06:00:00', '2024-10-20 00:55:06', '2019-06-09 06:00:00', 'terapia', 'inactivo', 12, 0),
	(38, 'Cartas Astrales.', 'cartas-astrales', 'Todas tus dudas e interrogantes las responderemos con el arte de la Astrología. Elaboradas por reconocida Astróloga y Tarotista', '<h4>Todas tus dudas e interrogantes las responderemos con el\r\narte de la Astrología. Elaboradas por reconocida Astróloga y Tarotista</h4><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">1.- Estudio Astrológico de la Carta Natal 2.- Carta Kármica\r\n3.- Horóscopo de pareja 4.- Progresiones planetaria 5.-Informe Astrológico\r\nVocacional 6.- Informe Astrológico Infantil</p><h5>¿Qué es la Astrología?</h5><p class="MsoNormal"><o:p></o:p></p><p class="MsoNormal">La astrología es una ciencia y un arte a la vez&nbsp; que estudia la influencia de los astros sobre\r\nlos acontecimientos acerca de la vida en la tierra.</p><p class="MsoNormal">La posición de los planetas, el Sol y la Luna en el momento\r\nexacto del nacimiento de una persona, animal, país, empresa o cualquier otra\r\nentidad, tiene gran influencia sobre su personalidad, salud, profesión y por\r\ntanto en su destino.</p><h5>¿Qué es y para qué sirve una Carta Natal?</h5><p class="MsoNormal">Se considera a la carta astral como un medio para conocerse\r\nmejor y utilizar las cualidades personales de cada uno y para superar los\r\nobstáculos que la vida te ponga en el camino.&nbsp;\r\nConsiste en el estudio de la fecha, lugar y hora de nacimiento de una\r\npersona y, según su posición, analiza cómo influyen los planetas en tu destino.</p><h5>También sirve para analizar los siguientes temas:</h5><p class="MsoNormal">1. Tu personalidad y tu carácter: te ayudará tomar\r\ndecisiones, conocer tu potencial y cómo desarrollarlo.</p><p class="MsoNormal">2. Economía y desarrollo financiero: como se desarrollará y\r\ncómo mejorar este aspecto.</p><p class="MsoNormal">3. Tu vida amorosa y afectiva: ¿serás feliz en el amor? ¿te\r\ncasarás? ¿cómo será tu marido?</p><p class="MsoNormal">4. Relaciones sociales: te ayudará a elegir mejor tus\r\namistades, saber si tendrás problemas con ellas y cómo superarlos.</p><p class="MsoNormal">5. Trabajo: cómo desarrollar tu potencial profesional al\r\nmáximo. Qué deberías hacer.</p><p class="MsoNormal">6. El hogar y la familia: Cómo será tu familia o cómo\r\nsolucionar los problemas en torno a ella. Caminos que deberías tomar y\r\ncualidades que podrías potenciar para estar mejor.</p><h5>¿Qué es y para que una Carta Karmica?</h5><p class="MsoNormal">El Estudio Astrológico Kármico muestra las influencias que\r\ntraemos de vidas pasadas y de las "asignatiras pendientes" que\r\nvenimos a "recursar" en nuestro proceso evolutivo y cómo lo\r\ntrabajaremos.</p><h5>¿Qué es y para que el Horóscopo de pareja?</h5><p class="MsoNormal">El Estudio Astrológico de Pareja, analiza las posiciones\r\nplanetarias de dos personas e indican cómo se relacionarán en todos los\r\nsentidos y dando a conocer los puntos fuertes y los poco fáciles de manejar en\r\nuna relación y también se da a conocer si es posible superar los obstáculos que\r\nse presenten en diversos ámbitos.</p><h5>¿Qué son y para qué las Progresiones Planetarias?</h5><p class="MsoNormal">Las Progresiones Planetarias es un estudio que se basa en la\r\nposición de los Astros y Planetas en el día del nacimiento y cómo se encuentran\r\nen la actualidad, cuando ´´estos se colocan a 30, 45, 60, 90 ó 180 grados,\r\nforman "aspectos" y estos determinan las vivencias por las que está\r\natravesando la persona y cómo puede manejarlas.</p><h5>¿Qué es y para qué sirve un informe Astrológico vocacional?</h5><p class="MsoNormal">El Estudio Astrológico Vocacional analiza el Signo Solar,\r\nLunar, del Ascendente y de todas las posiciones planetarias que determinan la\r\npersonalidad, el carácter y los talentos de una persona que lo inclinan a\r\nprofesiones específicas y de todas ellas, la persona elegirá la que más le\r\natraiga-</p><h5>¿Qué es y para qué un informe astrológico infantil?</h5><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p class="MsoNormal">El Estudio Astrológico Infantil es una especia de Manual de\r\nOperación de un niño, de acuerdo a la posición del Sol, Luna y el Ascendente,\r\nse indica cómo se debe alentar, restringir, alimentar, curar al niño para tener\r\nun desarrollo integral sano y además la influencia que ejercerán los padres.<o:p></o:p></p>', 'publicacion-5cfc67ca2fb9a.jpg', 0, '2019-06-09 06:00:00', '2021-06-08 19:12:02', '2019-06-09 06:00:00', 'terapia', 'inactivo', 13, 0),
	(39, 'Reiki Tibetano', 'reiki-tibetano', 'Es un sistema mucho más potente y profundo que contiene diferentes sistemas de curación, potencia y profundiza mucho mas.', '<p>Es un sistema mucho más potente y profundo que contiene diferentes sistemas de curación, potencia y profundiza mucho mas</p><p>La meta es conseguir la salud integral del individuo y la premisa para lograr esto es fomentar la felicidad propia y la de los demás.</p>', 'publicacion-5cfc681bd7b72.jpg', 0, '2019-06-09 06:00:00', '2019-06-10 17:12:08', '2019-06-09 06:00:00', 'terapia', 'activo', 14, 0),
	(40, 'Reiki Angélico', 'reiki-angelico', 'Es trabajar mano a mano con el Reino Angélico de luz para traer una de las formas más elevadas de sanación para individuos, grupos y el planeta. Los ángeles son Maestros, los ascendidos del universo, a través de su guía el arte sanador de Reiki puede actuar en el ser a nivel mental, emocional y físico.', '<p><span style="color: rgb(51, 51, 51); font-family: "Helvetica Neue", Helvetica, Arial, sans-serif; font-size: 14px;">Es trabajar mano a mano con el Reino Angélico de luz para traer una de las formas más elevadas de sanación para individuos, grupos y el planeta. Los ángeles son Maestros, los ascendidos del universo, a través de su guía el arte sanador de Reiki puede actuar en el ser a nivel mental, emocional y físico.</span><br></p>', 'publicacion-6185dadf42d06.jpg', 0, '2019-06-09 06:00:00', '2021-11-06 01:31:11', '2019-06-09 06:00:00', 'terapia', 'activo', 15, 0),
	(41, 'Constelaciones Familiares', 'constelaciones-familiares', 'Sanando tu historia, abrazando tu destino ', '<div><div>Sanando tu historia, abrazando tu destino </div><div><br></div><div>Querid@ alma en búsqueda de luz y transformación,</div><div>En cada uno de nosotros habita la memoria de nuestro linaje, una red invisible que nos conecta con nuestros ancestros, sus alegrías, sus dolores, sus secretos y sus anhelos no cumplidos. Muchas veces, sin darnos cuenta, cargamos con lealtades inconscientes que nos limitan, patrones que se repiten y bloqueos que nos impiden vivir en plenitud.</div><div>Las Constelaciones Familiares son un camino profundo de sanación, una oportunidad para mirar con amor y comprensión aquello que en nuestro árbol genealógico sigue pidiendo ser reconocido y liberado. A través de esta poderosa herramienta, podemos:</div></div><div><br></div><ul><li><span style="font-size: 13px;">Sanar relaciones familiares y encontrar la armonía en nuestros vínculos.</span></li><li><span style="font-size: 13px;">Liberarnos de patrones heredados que nos impiden avanzar en la vida.</span></li><li><span style="font-size: 13px;"> Soltar cargas emocionales y energéticas que no nos pertenecen.</span></li><li><span style="font-size: 13px;"> Reconectar con la fuerza de nuestros ancestros para vivir con mayor propósito.</span></li><li><span style="font-size: 13px;"> Descubrir la raíz de bloqueos emocionales, laborales y de pareja para transformarlos.</span></li></ul><h4><span style="font-size: 13px;"><br></span></h4><h4><span style="font-size: 13px;">Este es un llamado del alma, una invitación a mirar con amor lo que ha sido, para abrirnos a lo que puede ser. Cuando sanamos, no solo nos liberamos a nosotros mismos, sino que también sanamos a quienes vinieron antes y a las generaciones que vendrán después.</span></h4><h4><span style="font-size: 13px;"><br></span></h4><h4><span style="font-size: 13px;">Si sientes en tu corazón que es el momento de dar este paso, te invito a vivir la experiencia de una sesión de Constelaciones Familiares. Junt@s, honraremos tu historia y abriremos el espacio para que la energía del amor y la reconciliación traiga claridad, paz y sanación a tu vida.</span></h4><h4><span style="font-size: 13px;"><br></span></h4><h4><span style="font-size: 13px;">El momento es ahora. Confía, suelta y permite que la magia de la sanación actúe en ti.</span></h4><h4><span style="font-size: 13px;"><br></span></h4><h4><span style="font-size: 13px;">Con amor, gratitud y recuerda,</span></h4><h4><span style="font-size: 13px;">Tu luz transforma el mundo</span></h4><h4><span style="font-size: 11px;"></span></h4>', 'publicacion-5cfc686967e5d.jpg', 0, '2019-06-09 06:00:00', '2025-02-12 20:05:18', '2019-06-09 06:00:00', 'terapia', 'activo', 16, 0),
	(42, 'Registros Akáshicos', 'registros-akashicos', 'Los Registros Akáshicos son una base de información ilimitada, del pasado, presente y futuro desde el origen de tu alma.', '<p class="MsoNormal">Los Registros Akáshicos contienen el conocimiento presente y pasado, las experiencias y expresiones del recorrido del Alma, desde su inicio hacia adelante, así como todas las posibilidades de su futuro desarrollo. Hacen alusión a los recuerdos de nuestra alma, recuerdos que han sido guardados a través de todas las vidas que hemos atravesado.</p><p class="MsoNormal">Está todo el historial de los procesos por los que ha pasado el alma y que la han llevado a niveles cada vez más elevados de consciencia, así como las pruebas a las que ha sido sometida.</p><p class="MsoNormal">Acceder a los Registros Akáshicos supone tener información de todo el conocimiento de todas las cosas, desde las más cercanas a las más remotas o lejanas. Desde nuestra propia vida hasta el origen del Universo. Desde obtener respuestas al porqué nos suceden determinados acontecimientos en nuestra vida actual a cualquier acontecimiento de vidas pasadas.</p><p class="MsoNormal">Una lectura de Registros consiste en abrir el Registro del alma, permitiendo que llegue la información necesaria para nuestro progreso, avance y evolución.</p><p class="MsoNormal">Al acceder a los Registros, el consultante, a través del lector, obtiene la información que su Alma necesita comunicarle a la personalidad, por lo general atascada en el velo de la realidad, para que pueda evolucionar de acuerdo al Plan elegido por el Ser encarnado.</p><p class="MsoNormal">La información específica que concierne a vidas pasadas puede o no ser relevante. Lo realmente valioso, es en la guía, la orientación que se recibe para elaborar y trabajar mejor los patrones que están presentes en esta vida, las oportunidades para crecer y la dirección más apropiada a tomar en este momento.</p><p class="MsoNormal">Hacerse una lectura de Registro Akáshico implica tomar conocimiento de todas aquellas experiencias que pueden servirnos para desarrollarnos en el aquí y ahora, tomar contacto quizás con lo que eventualmente pudiéramos no estar haciendo para evolucionar y así poder corregirnos. Es una oportunidad única de reorientar nuestra vida hacia su verdadero camino, alivianando el karma que quizás no nos permite avanzar.</p><p class="MsoNormal">A través de los Registros Akáshicos se puede leer, como en un libro abierto, la totalidad de nuestras vidas: pasado, presente y futuro. Todo coexistiendo en un mismo plano y abarcando todos nuestros pensamientos, emociones, aprendizaje, luz y sombra. A través de su lectura, llegamos a conocernos más.&nbsp; Intentamos ver cuáles son los patrones de comportamiento que nos hacen sentir separados de nuestra esencia. Podemos ver cuando empezaron esos síntomas de separación y podemos descubrir cómo quizás nos llegaron patrones erróneos a través de nuestro entorno y personas más cercanas, convirtiéndolos en nuestros y dificultando el fluir desde nuestra propia esencia para percibir y vivir la realidad. Una vez descubierto el origen, nuestros verdaderos sentimientos y pensamientos se abren paso hacia la vida que nos rodea.</p><p class="MsoNormal">Es difícil lograr un cambio cuando no nos conocemos. Por eso es importante tener información sobre las acciones y hechos pasados, pues todos tenemos patrones de comportamiento que se repetirán si no tenemos conocimiento de ello. Una vez que sabemos de dónde viene un determinado patrón, podemos cambiar nuestra respuesta ante una situación y vivirla de forma diferente.</p><p class="MsoNormal">Trabajar con los Registros es mirar profundamente en nuestro interior para liberar, sanar, comprender y amar, pues contienen la historia de cada chispa divina, que es nuestra alma desde el principio de los tiempos.</p><p class="MsoNormal">Todos tenemos la capacidad de conectar con los Registros Akáshicos. Todo el conocimiento está ahí para servirnos en nuestro camino evolutivo.</p><h5>Algunas preguntas claves que pueden realizarse en una Lectura de Registros Akáshicos&nbsp; tenemos:</h5><ul><li>¿Cuál es mi misión de vida?</li><li>¿Por qué razón estoy aquí?</li><li>¿Quiénes son mis guías?</li><li>¿cuál es el próximo paso a seguir en…?</li><li>¿Por qué siempre que comienzo algo no lo concluyo?</li><li>¿Cómo puedo desbloquear mi vida afectiva?</li><li>¿Qué tengo que aprender de esta situación?</li><li>¿Qué relación tuve en vidas pasadas con...?</li><li>¿Cómo puedo mejorar mi calidad de vida en....?</li><li>¿Qué necesito para mejorar mi calidad espiritual?</li><li>¿Cómo mejorar mi situación con...?</li><li>¿Qué es lo que vengo a aprender en esta encarnación?</li><li>¿Por qué elegí esta familia para nacer?</li><li>¿Qué habilidades o aprendizajes de mis vidas pasadas podría recordar para realizar mejor mi plan de vida actual?</li><li>¿Qué cosas de mis vidas pasadas podría mejorar?</li><li>¿Cómo mejorar mi calidad de vida actual?</li><li>¿Tengo algún condicionamiento, pacto, contrato o promesa de alguna vida pasada conmigo mismo, con otros o algo que me esté afectando en forma negativa el momento actual?</li><li>¿Qué es necesario aprender de la familia en que nací?</li><li>¿Qué cosas son necesarias desprenderme para llevar a cabo mejor mi plan de vida?</li><li>¿Cómo puedo estar más cerca de mis ángeles, guías, maestros y ancestros?</li><li> ¿Cómo me expando?</li><li> ¿Cómo puedo mejorar mi sentido de conexión conmigo mismo, con los demás y con la Tierra? </li><li>Estoy buscando una comprensión más profunda sobre mi vida: ¿Qué puedo entender, liberar o cambiar para encontrar una comprensión más profunda sobre mi vida? ¿Cómo encuentro un sentido de lo espiritual en mi vida cotidiana? </li><li>Estoy pensando en mudarme: ¿Por qué tengo ganas de moverme? ¿Qué me detiene en el lugar que estoy? ¿Qué necesito liberar para mudarme a un nuevo lugar (literal o metafórico)?&nbsp;</li><li> Quiero sentirme más seguro/a: ¿Qué puedo hacer para mejorar mi capacidad de confiar en mí mismo/a? </li><li>Soy consciente de que estoy cambiando mi vida: ¿Qué estoy aprendiendo sobre mí? ¿Qué posibilidades me están esperando? </li><li>Me siento solo/a: ¿Cómo encuentro mi conexión con otros, con Dios, conmigo mismo? </li><li>Me siento asustado/a: ¿De qué tengo miedo? ¿Cómo lo cambio? </li><li>¿Qué necesito entender sobre mi papel en la familia? ¿Qué necesito para cambiar mis creencias sobre la familia? </li><li>Estoy luchando en una relación con mi pareja: ¿Dónde estoy atrapado en mi relación? ¿Qué necesito dejar? ¿Cómo puedo dejar de lado las cosas que me molestan en la relación? </li><li>Me siento desenfocado/a: ¿Qué aspectos de mi vida no estoy atendiendo? ¿Qué está alejando mi atención de lo que quiero? ¿Dónde necesito dirigir mi atención? </li><li>Me siento triste: ¿Cuál es la fuente de mi tristeza? ¿Es mi tristeza un síntoma de un problema o sentimiento más profundo? </li><li>Mis hijos no me escuchan: ¿Es cierto que mis hijos no me escuchan? ¿Cómo puedo cambiar lo que digo para que mis hijos me escuchen? </li><li>Estoy frustrado/a con mis hijos: ¿Cuál es la raíz del problema de mi frustración con mis hijos? ¿Qué puedo hacer para cambiar la relación con mis hijos para que todos estemos felices? </li><li>Estoy cansado de ir a terapia: ¿Qué puedo entender de mí mismo/a que me ayudará a sentirme mejor acerca de mi vida? </li><li>No estoy contento con mi cuerpo físico: ¿Qué hay de mi ser físico en el que estoy decepcionado, no me gusta o no lo entiendo? ¿Qué puedo hacer para cambiar mi mala opinión de mí mismo? ¿Qué llevo que puedo dejar ir? </li><li>No siento que pertenezca a la Tierra: ¿Por qué tengo esta sensación? ¿Qué puedo hacer para sentirme más conectado? </li><li>¿Cuáles son mis dones, habilidades y herramientas para vivir más en coherencia y en paz?</li><li> ¿Qué aprendizaje hay detrás de esta experiencia? </li><li>¿Qué me quiere decir esto que tanto se repite en mi vida?</li><li>¿Cuáles son mis principales cualidades y qué debo hacer para potenciarlas en el ámbito (laboral, personal, familiar…)? </li><li>¿Qué necesito hacer para lograr tal cosa o situación en mi vida? </li><li>¿Qué requiere mi atención, tiempo en este momento? </li><li>¿Qué acción puedo realizar para conseguir “esta” meta en el ámbito personal, laboral, empresarial? </li><li>¿Qué opciones tengo para alcanzar mis objetivos? </li><li>¿Cómo vivo el amor, compasión, pasión (etc.) en mi vida? </li><li>¿Dónde y cómo puedo aplicar mis conocimientos para mi mayor beneficio en el ámbito personal, laboral, empresarial, organizacional…? </li><li>¿Cómo obtengo ayuda para…? </li><li>¿Cómo modifico mis creencias, qué acciones podría realizar? </li><li>¿Qué me genera tensión y cómo lo cambio? </li><li>¿De dónde viene/Por qué tengo esta sensación de soledad, tristeza, ira y qué debo hacer para sacarlo de mi vida? </li><li>¿De dónde vienen estos patrones que se repiten en esta situación, con esta persona…? </li><li>¿Qué he venido a vivir a nivel de alma con esta persona? </li><li>¿Qué patrones o creencias limitantes me impiden desplegar todo mi potencial? </li><li>¿Por qué me cuesta llevar a cabo esto que tanto anhelo, deseo? </li><li>¿Qué me está bloqueando mi capacidad para generar prosperidad en mi vida? </li><li>¿Por qué o para qué me sucedió esta situación, esto que viví? </li><li>¿De dónde viene/Por qué se repite este modelo/patrón en mi vida?&nbsp;</li><li>¿De dónde viene mi miedo de/a… ? </li><li>¿Qué no estoy viendo/ qué tengo que aprender de esta relación o situación?&nbsp; </li><li>¿Qué mensaje me está intentando dar esta enfermedad o dolencia y cómo la puedo sanar/mejorar/transformar? </li><li>¿Qué puedo aprender de…?</li><li>¿Qué me quita tiempo, vitalidad en mi vida? </li></ul><p><span style="background-color: rgb(255, 255, 0);"><br></span></p><p><b style="background-color: inherit;">Preguntas sobre traumas o posible necesidad de curación</b></p><ul><li>¿Qué trauma, dolor, miedo o ira me alejan de la conciencia de integridad, equilibrio y conexión plena? </li><li>Este horrible evento ocurrió en mi infancia y siento que todavía me detiene: ¿Qué puedo entender sobre este evento para seguir adelante? </li><li>Tengo períodos de mi vida que no recuerdo: ¿Qué pasó que no recuerdo estas partes de mi vida? ¿Qué traerá de vuelta mi memoria? </li><li>Me siento atrapado, como si algo me estuviera frenando: ¿Qué me detiene y cómo puedo liberarme? </li><li>Tengo miedo de volar, de la oscuridad, (cualquier miedo): ¿Por qué tengo este miedo? ¿Qué puedo hacer para liberarme? </li><li>Mi corazón se siente atrapado o contraído: ¿Qué puedo hacer para liberar este sentimiento en mi corazón? </li><li>No tengo sentimientos o me cuesta identificarlos: ¿Qué se interpone entre mis sentimientos y yo? ¿Qué puedo hacer para liberarlos? </li><li>Constantemente digo cosas negativas sobre mí: ¿Cuál es la fuente de la fuerza y el poder de mi voz crítica?</li></ul><p><b>Preguntas sobre la pareja: principio, fin y todo lo demás</b></p><ul><li>¿Cómo nos apoyamos mutuamente en el crecimiento tanto en la relación como individualmente? </li><li>Me siento listo para tener una relación más profunda con mi pareja: ¿Qué puedo hacer para expandir nuestra relación? ¿Hay algo en el camino de una relación más profunda?&nbsp;</li><li> Quiero entender mi relación con mi pareja: ¿Qué ofrezco y recibo dentro de esta asociación? ¿Qué puedo entender, cambiar o liberar para mejorar esta relación? </li><li>Siento que he perdido la conexión con mi pareja: ¿Dónde estoy ahora en relación con mi pareja? ¿De qué se trata la desconexión? ¿Qué puedo revelar o entender sobre esta relación? </li><li>Mi compañero/a hace comentarios crueles y críticos sobre mí: ¿Por qué son estos comentarios críticos para mí? ¿Cómo puedo aumentar mi confianza en mí mismo? </li><li>Mi pareja está teniendo una aventura: ¿Cuál es la verdad de este asunto para mí? ¿Cómo trato con el dolor de la traición? </li><li>Tengo miedo de mi pareja: ¿Cuál es la verdad de la relación con mi pareja? ¿Por qué le tengo miedo a mi pareja? </li><li>Siento que estoy al final de la relación con mi pareja: ¿Es el divorcio la mejor opción para mí? ¿Cómo procedo desde donde estoy en mi vida? ¿Cuál es mi camino hacia una mayor felicidad? </li></ul><p><b>Preguntas sobre las posibilidades del alma </b></p><ul><li>Quiero entender el propósito o la misión de mi alma: ¿Cuál es el propósito actual de mi vida? ¿Cómo puede avanzar hacia el logro de este propósito? </li><li>Siento que sigo haciendo cosas que no me ayudan: ¿Qué patrones ya no sirven? ¿Qué recibo por mantener este patrón? ¿Cómo puedo dejar de lado estos patrones? </li><li>Siento que mi alma me llama y no estoy seguro de lo que se dice: ¿Dónde escucho mi alma llamando? ¿Cómo puedo responder a la llamada? ¿De qué se trata la llamada en este momento? </li><li>Siento que algo sobre mi alma me está frenando: ¿Mi alma tiene ataduras que necesito saber y liberar ahora? ¿Cómo puedo liberar? </li></ul><p><br></p><p><b>Preguntas sobre trabajo, negocios y dinero</b> </p><ul><li>Amo lo que hago, pero no siento alegría: ¿Por qué no experimento alegría en mi trabajo? • Odio a mi jefe: ¿Cómo mantengo mi relación con mi jefe? ¿Qué espero de mi jefe? </li><li>No me gustan mis compañeros de trabajo. ¿Cómo me comparo con ellos? ¿Qué necesito entender sobre mi relación con ellos? </li><li>A mi jefe le gusta más mi compañero de trabajo que yo: ¿Por qué necesito la aprobación de mi jefe? ¿De quién más necesito aprobación? </li><li>No me gusta mi trabajo: ¿Qué es exactamente lo que no me gusta? ¿Qué temo de mi trabajo? </li><li>Quiero otro trabajo: ¿Qué espero obtener de otro trabajo? </li><li>No puedo esperar a que termine el día: ¿Qué necesito dejar? ¿Qué creo que hay en casa que no está en el trabajo? </li><li>Espero que mañana sea mejor: ¿Qué me impide estar en el momento presente? ¿Dónde necesito concentrarme? </li><li>Estoy cansado de este trabajo: ¿Qué más no es lo suficientemente bueno en mi vida? ¿Qué me traería un nuevo trabajo? </li><li>Quiero un ascenso: ¿Cómo me satisfaría una promoción?</li><li> Siempre me ha ido bien, pero las cosas son lentas: ¿Por qué siento que las cosas son lentas? ¿Qué puedo cambiar o liberar para que mi trabajo / negocio se mueva? ¿Qué estoy ignorando que sería útil reconocer? </li><li>Mi empresa está perdiendo dinero: ¿Por qué mi empresa está perdiendo dinero? Como propietario del negocio, ¿cómo puedo cambiar mi negocio y yo para pasar a la rentabilidad? </li><li>Mis productos no se venden: ¿Por qué no se venden mis productos? ¿Qué puedo hacer para mejorar las ventas? </li><li>Mi departamento no escucha mi guía: ¿Cuál es la verdad sobre la situación dentro de mi departamento en relación conmigo? ¿Qué puede ser diferente para que mi departamento me escuche? </li><li>Mi equipo se queja el uno del otro: ¿Cuáles son las dinámicas de mi equipo? ¿Cómo puedo aliviar la tensión dentro de mi equipo? ¿Cómo puedo cambiar mi equipo para que las quejas se detengan y avancemos felices juntos? </li><li>Soy demasiado duro con mi equipo: ¿Por qué exijo perfección? ¿Cómo puedo relajarme a mí mismo y a los demás? </li><li>No soy lo suficientemente fuerte con mi equipo: ¿Qué me impide ser un líder efectivo o sentir que soy un líder efectivo? </li></ul><p><br></p><p><br></p><p><b>RELACIONES KÁRMICAS </b></p><ul><li>¿Dónde se originó esta relación kármica? ¿Cómo? </li><li>¿Qué aprendizaje hay a nivel álmico con …? </li><li>¿Qué acordamos … y yo aprender? </li><li>A nivel álmico, ¿qué me une a ….? </li><li>¿Qué estamos trabajando a nivel álmico … y yo? </li><li>¿Dónde está el conflicto entre … y yo? </li><li>¿Cuáles son las relaciones kármicas que me relacionan con …? </li><li>¿Cuál es mi relación álmica con…? </li><li>¿Por qué me resulta tan difícil aceptar a … tal y como es? </li><li>¿Qué necesito para aceptar a … tal y como es? </li><li>¿Para qué he tenido … (la vivencia o experiencia que hayas tenido) con…? </li><li>¿Cómo puedo encontrar la paz entre nosotros? </li><li>¿De dónde viene mi vínculo kármico con…? </li><li>¿De qué otras herramientas dispongo para sanar la relación con…? </li><li>¿En qué me limita esta relación? </li><li>¿Qué parte de mí necesita esta relación? </li><li>¿Qué patrón hay en mí que genera esta relación? </li><li>¿Qué oportunidad de cambio trae a mi vida esta relación?&nbsp;&nbsp;</li></ul><p><br></p><p>&nbsp;&nbsp; <b>SITUACIONES&nbsp; </b></p><ul><li>¿Dónde se originó? ¿Cómo? </li><li>¿Cómo me limita esta situación? </li><li>¿Qué es lo que no logro aprender? </li><li>¿Por qué se repite esta situación en mi vida? </li><li>¿Cuál es la lección que debo sacar de este aprendizaje? </li><li>¿Por qué y para qué estoy en esta situación?</li><li>¿Qué estoy intentado aprender a nivel de alma con dicha situación? </li><li>¿Cómo puedo evolucionar a través de esta situación? </li><li>¿De dónde viene esta situación? </li><li>¿Cómo puedo trascender esta situación y pasar al siguiente nivel? </li><li>¿Qué patrón estoy haciendo para que se dé esta situación? </li><li>¿Qué parte de mí necesita esta situación? </li><li>¿De qué otras herramientas dispongo para sanar esta situación? </li><li>¿Qué oportunidad de cambio trae a mi vida esta situación?</li></ul><p><br></p><p><b>&nbsp;&nbsp; DONES </b></p><ul><li>¿Cuáles son las cualidades/dones que tengo que traer para…? </li><li>¿Qué tengo que hacer para traer … habilidad a mi vida? </li><li>¿A qué me niego/resisto para manifestar estos dones? </li><li>¿Cómo puedo hacer para traer estos dones a mi vida? </li><li>¿Cómo debo obrar para ponerlos a disposición de un plan mayor? </li><li>¿Cuáles son los pasos para traerlos? <br></li></ul>', 'publicacion-671457b6b3d07.jpg', 0, '2019-06-09 06:00:00', '2024-11-05 00:01:43', '2019-06-09 06:00:00', 'terapia', 'activo', 2, 0),
	(43, 'Numerología  ', 'numerologia', 'Hay distintas numerologías que parten de los principales y más antiguos alfabetos como el sánscrito (numerología tántrica), el judío (numerología cabalística) o el griego (numerología pitagórica). Cada una de ellas describe una faceta del cristal de nuestra encarnación y nos aporta una visión distinta y complementaria de nosotros mismos. La numerología de Ailexin, derivada de la tradición tántrica, estudia la fecha de nacimiento para orientarnos acerca de lo que venimos a aprender en esta encarnación, nuestras potencialidades, debilidades y retos.', '<p><span style="color: rgb(51, 51, 51); font-family: arial; font-size: 13.3333px;">Hay distintas numerologías que parten de los principales y más antiguos alfabetos como el sánscrito (numerología tántrica), el judío (numerología cabalística) o el griego (numerología pitagórica). Cada una de ellas describe una faceta del cristal de nuestra encarnación y nos aporta una visión distinta y complementaria de nosotros mismos. La numerología de Ailexin, derivada de la tradición tántrica, estudia la fecha de nacimiento para orientarnos acerca de lo que venimos a aprender en esta encarnación, nuestras potencialidades, debilidades y retos.</span></p><p><font color="#212529" face="Nunito, Segoe UI, Roboto, Helvetica Neue, Arial, sans-serif, Apple Color Emoji, Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji"><span style="font-size: 16px;">El estudio Numerológico analiza cinco aspectos las características del número de tu:</span></font><br></p><p class="MsoNormal" style="box-sizing: inherit; margin-bottom: 0.0001pt; color: rgb(33, 37, 41); font-family: Nunito, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji"; font-size: 16px; text-indent: 35.4pt; line-height: normal;">Alma</p><p class="MsoNormal" style="box-sizing: inherit; margin-bottom: 0.0001pt; color: rgb(33, 37, 41); font-family: Nunito, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji"; font-size: 16px; text-indent: 35.4pt; line-height: normal;">Personalidad</p><p class="MsoNormal" style="box-sizing: inherit; margin-bottom: 0.0001pt; color: rgb(33, 37, 41); font-family: Nunito, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji"; font-size: 16px; text-indent: 35.4pt; line-height: normal;">Regalo de Dios</p><p class="MsoNormal" style="box-sizing: inherit; margin-bottom: 0.0001pt; color: rgb(33, 37, 41); font-family: Nunito, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji"; font-size: 16px; text-indent: 35.4pt; line-height: normal;">Vida Pasada</p><p class="MsoNormal" style="box-sizing: inherit; margin-bottom: 0.0001pt; color: rgb(33, 37, 41); font-family: Nunito, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji"; font-size: 16px; text-indent: 35.4pt; line-height: normal;">Misión</p><p><br></p><p>y como se entrelazan entre ellos para darnos información que te permita encontrar la información que te ayude a encontrar los caminos, y bienestar en tu vida.</p>', 'publicacion-5cfc68b31c58c.jpg', 0, '2019-06-09 06:00:00', '2024-11-15 23:54:06', '2019-06-09 06:00:00', 'terapia', 'activo', 3, 0),
	(44, 'Sesión de Reiki Gratis', 'sesion-de-reiki-gratis', 'En tu cumpleaños, por que queremos consentirte.', '<p>En tu cumpleaños queremos consentirte.</p><p>Recibe una sesión de reiki GRATIS (valido en el mes de tu cumpleaños).</p>', 'publicacion-5cfc690b9ac2a.jpg', 0, '2019-06-09 06:00:00', '2021-10-28 17:58:07', '2019-06-09 06:00:00', 'promocion', 'inactivo', 0, 0),
