	(51, 'Galeria Teotihuacan. Pidiendo por la paz del Mundo, alimentando de energía a la Madre Tierra', 'galeria-teotihuacan-pidiendo-por-la-paz-del-mundo-alimentando-de-energia-a-la-madre-tierra', '', '', 'publicacion-5cfc792d9fac2.jpg', 0, '2019-06-09 06:00:00', '2025-11-25 17:33:32', '2019-06-09 06:00:00', 'galeria', 'activo', 67, 0),
