able 1 Light Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="47" Name="List Table 2 Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="48" Name="List Table 3 Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="49" Name="List Table 4 Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="50" Name="List Table 5 Dark Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="51"\r\n   Name="List Table 6 Colorful Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="52"\r\n   Name="List Table 7 Colorful Accent 6"></w:LsdException>\r\n </w:LatentStyles>\r\n</xml><![endif]--><!--[if gte mso 10]>\r\n<style>\r\n /* Style Definitions */\r\n table.MsoNormalTable\r\n	{mso-style-name:"Tabla normal";\r\n	mso-tstyle-rowband-size:0;\r\n	mso-tstyle-colband-size:0;\r\n	mso-style-noshow:yes;\r\n	mso-style-priority:99;\r\n	mso-style-parent:"";\r\n	mso-padding-alt:0cm 5.4pt 0cm 5.4pt;\r\n	mso-para-margin-top:0cm;\r\n	mso-para-margin-right:0cm;\r\n	mso-para-margin-bottom:8.0pt;\r\n	mso-para-margin-left:0cm;\r\n	line-height:107%;\r\n	mso-pagination:widow-orphan;\r\n	font-size:11.0pt;\r\n	font-family:"Calibri",sans-serif;\r\n	mso-ascii-font-family:Calibri;\r\n	mso-ascii-theme-font:minor-latin;\r\n	mso-hansi-font-family:Calibri;\r\n	mso-hansi-theme-font:minor-latin;\r\n	mso-bidi-font-family:"Times New Roman";\r\n	mso-bidi-theme-font:minor-bidi;\r\n	mso-fareast-language:EN-US;}\r\n</style>\r\n<![endif]-->\r\n\r\n</p><p class="MsoNormal">Curso Lector de Oráculos Angelicales</p>\r\n\r\n<p class="MsoNormal"> </p>\r\n\r\n<p class="MsoNormal">Este curso Oráculo de Ángeles está pensado en prepararte\r\npara que puedas trabajar como Lector profesional de Oráculos Angelicales.</p>\r\n\r\n<p class="MsoNormal">Aprende a conectarte con el mundo de los ángeles para\r\nrecibir sus mensajes de manera amorosa y asertiva para encontrar respuestas\r\nsobre tu vida o de la persona que te consulte.</p>\r\n\r\n<p class="MsoNormal">Este curso de Oráculo de Ángeles está altamente recomendado\r\npara todo tipo de público, con o sin experiencia en el tema. </p>\r\n\r\n<p class="MsoNormal">Algunos de los temas a revisar son: </p>\r\n\r\n<p class="MsoListParagraphCxSpFirst" style="text-indent:-18.0pt;mso-list:l0 level1 lfo1"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">1.<span style="font:7.0pt " times="" new="" roman""="">     \r\n</span></span></span>¿Que es un oráculo?</p>\r\n\r\n<p class="MsoListParagraphCxSpMiddle" style="text-indent:-18.0pt;mso-list:l0 level1 lfo1"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">2.<span style="font:7.0pt " times="" new="" roman""="">     \r\n</span></span></span>Preparación del mismo</p>\r\n\r\n<p class="MsoListParagraphCxSpMiddle" style="text-indent:-18.0pt;mso-list:l0 level1 lfo1"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">3.<span style="font:7.0pt " times="" new="" roman""="">     \r\n</span></span></span>Meditación Angelical</p>\r\n\r\n<p class="MsoListParagraphCxSpMiddle" style="text-indent:-18.0pt;mso-list:l0 level1 lfo1"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">4.<span style="font:7.0pt " times="" new="" roman""="">     \r\n</span></span></span>Chakras</p>\r\n\r\n<p class="MsoListParagraphCxSpMiddle" style="text-indent:-18.0pt;mso-list:l0 level1 lfo1"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">5.<span style="font:7.0pt " times="" new="" roman""="">     \r\n</span></span></span>Las cuatro claris</p>\r\n\r\n<p class="MsoListParagraphCxSpMiddle" style="text-indent:-18.0pt;mso-list:l0 level1 lfo1"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">6.<span style="font:7.0pt " times="" new="" roman""="">     \r\n</span></span></span>Preparación tuya y del usuario</p>\r\n\r\n<p class="MsoListParagraphCxSpLast" style="text-indent:-18.0pt;mso-list:l0 level1 lfo1"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">7.<span style="font:7.0pt " times="" new="" roman""="">     \r\n</span></span></span>Tipos de tiradas, entre otros.</p>\r\n\r\n<p class="MsoNormal"> </p>\r\n\r\n<p class="MsoNormal"> </p>\r\n\r\n<p class="MsoNormal">Pregunta por este nuevo curso.</p><p class="MsoNormal"><br></p><p class="MsoNormal"><br></p><p class="MsoNormal"><br></p><p class="MsoNormal"><br></p><p class="MsoNormal"><br></p><p class="MsoNormal"><br></p><p class="MsoNormal">Av Miguel Hidalgo No 23 b Col Bosques de México, Tlalnepantla, Estado de México.  <br></p>\r\n\r\n', 'publicacion-5ec03d4e155cb.jpg', 0, '2020-05-16 06:00:00', '2025-07-04 00:43:57', '2020-05-16 06:00:00', 'cursos', 'activo', 13, 0),
	(89, 'Cursos en Línea', 'cursos-en-linea', '', '', 'publicacion-5f13794bb4b95.jpg', 0, '2020-07-18 06:00:00', '2025-11-25 17:33:32', '2020-07-18 06:00:00', 'galeria', 'activo', 36, 0),
	(90, 'Reiki Japonés 2020', 'reiki-japones-2020', '', '', 'publicacion-5f13804baab76.jpg', 0, '2020-07-18 06:00:00', '2025-11-25 17:33:32', '2020-07-18 06:00:00', 'galeria', 'activo', 37, 0),
	(93, 'Héctor Nuñez Manrique', 'hector-nunez-manrique', 'Gracias a lo enseñado en Tamashi yo pude encontrar paz y calma en mi vida, superé traumas y encontré el camino de nuevo. Considero de gran bendición el poder contar con un maestro y guía en el camino de la luz y la energía universal. Sin duda recomiendo asistir a terapias o mejor aún a emprender el viaje al autoconocimiento a través de los cursos.', '<ul><li>Maestro en 5 sistemas de Reiki (Japonés, tibetano-tantrico, Angélico, Karuna y Egipcio)</li><li>Especialidades en : Cromoterapia, Reprogramación y Chamanismo</li><li> Lector de Registros Akashicos</li><li> Tarotista</li><li>Lector de Oráculos Angelicales</li><li> Numerologo </li><li>Constelador Familiar.</li><li>Angelologo</li><li>Angeloterapeuta</li><li>Flores de Bach</li><li>Terapeuta Transgeneracional</li><li>Sanador del Altísimo Dios del Universo</li><li>Facilitador de Ceremonias Holísticas</li></ul>', 'publicacion-613cf9b91af8a.jpg', 0, '2021-09-07 06:00:00', '2025-07-21 19:46:53', '2021-09-07 06:00:00', 'egresado', 'activo', 0, 0),
	(94, 'Rafael Alejandro Gutiérrez Lara', 'rafael-alejandro-gutierrez-lara', 'Para mí el Reiki ha sido un camino de autoconocimiento  y transformación, gracias a lo aprendido en TAMASHI he logrado encontrar el camino de la luz, y del servicio, es un parteaguas en mi vida antes y después.\r\nEn TAMASHI no solo encuentras un guía, encuentras un magnifico Maestro, amigos, compañeros. Todos  y cada uno de los cursos que TAMASHI ofrece contribuye a tu crecimiento espiritual y humano.\r\nA nivel personal me ha ayudado a liberarme de piedras del pasado, y ver el mundo con una visión más alegre, encontrar un equilibrio y una armonía, un autoconocimiento que desconocía, además que te lleva de la mano para desarrollar tus cualidades que desconocías tener.', '<ul><li>Maestro en 5 sistemas de Reiki (Japonés, tibetano-tántrico, Angélico, Karuna y Egipcio)</li><li>Especialidades en : Cromoterapia, Reprogramación y Chamanismo</li><li> Numerólogo</li><li>Lector de Oráculos.</li><li>Angelólogo&nbsp;</li><li>Angeloterapeuta</li><li>Terapeuta Transgeneracional</li><li>Sanador del Altísimo Dios del Universo</li><li>Tarotista</li><li>Terapeuta Flores de Bach</li><li>Constelador Familiar</li><li>Lector de Registros Akáshicos</li></ul>', 'publicacion-613a840bda020.jpg', 0, '2021-09-09 06:00:00', '2024-12-04 03:10:30', '2021-09-09 06:00:00', 'egresado', 'activo', 1, 0),
	(95, 'Fanny Anahí Lozano Nava', 'fanny-anahi-lozano-nava', 'Tamashi ha significado un antes y después en mi vida, agradezco a mi maestro como paciente y como aprendiz porque en mi persona hubo y esta fluyendo una evolución desde las terapias como paciente hasta los cursos impartidos,excelente en toda la extensión de la palabra. Gracias por peemitirme ser parte de esta gran experiencia.', '<ul><li>Maestra en 4 sistemas de Reiki (Japonés, tibetano-tantrico, Angélico, \r\nKaruna Prakriti)</li><li>Especialidades en : Cromoterapia, Reprogramación y Chamanismo</li><li>Lectora de Oráculos Angelicales</li><li>Tarotista</li><li>Numerologa</li><li>Consteladora Familiar.</li><li>Angelóloga</li><li>Angeloterapeuta</li><li>Facilitadora de Ceremonias Holísticas</li></ul><div></div>', 'publicacion-613aca98351f8.jpg', 0, '2021-09-09 06:00:00', '2025-07-21 19:47:17', '2021-09-09 06:00:00', 'egresado', 'activo', 2, 0),
	(96, 'Jesús Curiel Najera', 'jesus-curiel-najera', 'Tomar Reiki me trajo paz,   armonía y salud a mi vida y a la de mis seres queridos es una nueva forma de visualizar de l mundo.', '<ul><li>Maestro en Reiki Japonés. </li><li>Especialidades en : Cromoterapia, Reprogramación y Chamanismo.</li></ul>', 'publicacion-613b9195693a4.jpg', 0, '2021-09-10 06:00:00', '2024-12-03 20:54:28', '2021-09-10 06:00:00', 'egresado', 'activo', 30, 0),
	(97, 'María de Jesús Rojas Molina', 'maria-de-jesus-rojas-molina', ' Un día mi amiga Jazmín, me dijo: te regalo una lectura de tarot yo dije claro, y me cito en Tamashii, jajaja yo iba por una lectura. Al llegar al lugar lo vi muy agradable, me hicieron mi lectura; eso fue en el año 2018 desde entonces conocí algunos de los cursos que se impartían en Tamashii y literal me gustó tanto el primer curso que sigo ahí, y en espera de más cursos; mi vida a cambiado, mi forma de conducirme en la vida, la manera en la que manejo mi energía, mi paz interior, el aprendizaje para transitar la vida de la mejor manera. Ya no voy corriendo por la vida en Tamashi he aprendido a tener paz mental, tranquilidad y que las cosas tienen un porque y para que. Disfruto cada día de mi vida. Gracias TAMASHII ', '<ul><li style="box-sizing: inherit;">Maestra en 5 sistemas de Reiki (Japonés, tibetano-tantrico, Angélico, Karuna y Egipcio)</li><li>Especialidades en : Cromoterapia, Reprogramación y Chamanismo</li><li style="box-sizing: inherit;">Reikista para mascotas.</li><li style="box-sizing: inherit;">Lector de Oráculos Angelicales</li><li style="box-sizing: inherit;">Numerologo</li><li style="box-sizing: inherit;">Constelador Familiar.</li><li style="box-sizing: inherit;">Angelologo</li><li style="box-sizing: inherit;">Angeloterapeuta</li><li style="box-sizing: inherit;">Flores de Bach</li><li style="box-sizing: inherit;">Angelóloga</li><li style="box-sizing: inherit;">Angeloterapeuta</li><li style="box-sizing: inherit;">Terapeuta Transgeneracional</li><li style="box-sizing: inherit;">Sanador del Altísimo Dios del Universo</li><li>Facilitadora de Ceremonias Holísticas</li></ul><div></div>', 'publicacion-613cf86f98ab8.jpg', 0, '2021-09-11 06:00:00', '2025-07-21 19:47:45', '2021-09-11 06:00:00', 'egresado', 'activo', 3, 0),
	(98, 'Mary Carmen Hernández García', 'mary-carmen-hernandez-garcia', 'En Tamashi he vivido experiencias únicas en cada sesión, cada día es una experiencia de amor, conocimiento y paz.', '<ul><li>Maestría en Reiki Japonés.</li><li>Lectora de Oráculos Angelicales</li><li>Numerologa</li><li>Angelóloga</li><li>Angeloterapeuta</li><li>Terapeuta Transgeneracional</li><li>Sanadora del Altísimo Dios del Universo</li><li>Facilitadora de Ceremonias Holísticas</li></ul>', 'publicacion-613e2fe74e245.jpg', 0, '2021-09-12 06:00:00', '2025-07-21 19:48:06', '2021-09-12 06:00:00', 'egresado', 'activo', 4, 0),
	(99, 'Jaime  Yañez Cruz', 'jaime-yanez-cruz', '"Inicié mi contacto con Tamashi y el maestro José Luis como la respuesta a una inquietud que tenía años atrás de conocer el Reiki, como todo lo que vale la pena, apareció su página por accidente en mi buscador y decidí tomar acción para prepararme.\r\nGracias a su guía he aprendido, pero sobre todo he sentido un entendimiento de lo que realmente soy en forma integral, además de que he aceptado con mayor paz sucesos que antes me habría costado superar.\r\nGracias!!!"', '<ul style="box-sizing: inherit; color: rgb(33, 37, 41); font-family: Nunito, " segoe="" ui",="" roboto,="" "helvetica="" neue",="" arial,="" sans-serif,="" "apple="" color="" emoji",="" "segoe="" ui="" symbol",="" "noto="" emoji";="" font-size:="" 16px;"=""><li style="box-sizing: inherit;">Maestro en 5 sistemas de Reiki (Japonés, tibetano-tantrico, Angélico, Karuna y Egipcio)</li><li style="box-sizing: inherit;">Reikista para Mascotas</li><li style="box-sizing: inherit;">Especialidades en : Cromoterapia, Reprogramación y Chamanismo</li><li style="box-sizing: inherit;">Angelólogo</li><li style="box-sizing: inherit;">Angeloterapeuta</li><li style="box-sizing: inherit;">Terapeuta Transgeneracional</li><li style="box-sizing: inherit;">Sanador del Altísimo Dios del Universo</li><li>Facilitador de Ceremonias Holísticas</li></ul>', 'publicacion-613e33bdd5fae.jpg', 0, '2021-09-12 06:00:00', '2025-07-21 19:48:53', '2021-09-12 06:00:00', 'egresado', 'activo', 5, 0),
	(100, 'Edna Centenero Alcalá', 'edna-centenero-alcala', 'En este mundo tan ajetreado y tan violento, hay veces que sentimos que perdimos el rumbo, el no saber ni quienes somos y de lo que somos capaces nos llena de tristeza, enojo, frustración, pero al conocer todo lo que podemos hacer para ayudarnos y para ayudar a nuestro alrededor, te abre un nuevo panorama y nos llena de esperanza, de vida y eso lo conseguimos gracias al despertar espiritual, y yo lo he conseguido en Tamashi, los cursos que he tomado me han ayudado a sanar mis heridas, a dejar ir todo lo que no es mío y aceptar a las personas tal cual son, porque he llegado a comprender que todos tenemos un tiempo de despertar y gracias al maestro José Luis que nos hace las clases muy divertidas y fáciles de entender mi despertar llego.\r\nGracias maestro, gracias Tamashi!!!', '<ul segoe="" ui",="" roboto,="" "helvetica="" neue",="" arial,="" sans-serif,="" "apple="" color="" emoji",="" "segoe="" ui="" symbol",="" "noto="" emoji";="" font-size:="" 16px;"="" style="box-sizing: inherit; color: rgb(33, 37, 41); font-family: Nunito, "><li style="box-sizing: inherit;">Maestra en 3 sistemas de Reiki (Japonés, Angélico y Egipcio)</li><li style="box-sizing: inherit;">Especialidades en : Cromoterapia, Reprogramación y Chamanismo</li><li style="box-sizing: inherit;">Numeróloga</li><li style="box-sizing: inherit;">Angelológa</li><li style="box-sizing: inherit;">Angeloterapeuta</li><li style="box-sizing: inherit;">Terapeuta Transgeneracional</li><li style="box-sizing: inherit;">Sanadora del Altísimo Dios del Universo</li><li>Facilitadora de Ceremonias Holísticas</li></ul>', 'publicacion-613e531b21144.jpg', 0, '2021-09-12 06:00:00', '2025-07-21 19:48:19', '2021-09-12 06:00:00', 'egresado', 'activo', 6, 0),
	(101, 'Bertha Leticia García Olivares', 'bertha-leticia-garcia-olivares', 'Y sin darme cuenta encontré un remanso de paz, conocimiento y conexión con Dios que jamás imaginé posible, Joselo (mi maestro) tomó mi mano y acompaño mi camino hacia el reencuentro con mi espiritualidad, con ese ser Crístico del que muchos hablan y pocos experimentan. Desde ese momento se comprometió a compartir sus conocimientos en este mundo maravilloso y desconocido para mi, su ética y pasión por contribuir a la expansión de la conciencia colectiva hacen de Tamashi una experiencia de vida, ahí encontré conocimiento, entendimiento y amor, son una comunidad luminosa que se antoja, sin dudar, familiar, entrañable…\r\nGracias a todos aquellos que han pasado y pasarán por este maravilloso lugar nutriendo con su experiencia nuestro amado Tamashi', '<ul><li>Maestra en 4 sistemas de Reiki (Japonés, tibetano-tantrico, Angélico, Karuna)</li><li>Especialidades en : Cromoterapia, Reprogramación y Chamanismo</li><li> Lector de Registros Akashicos</li><li> Tarotista</li><li>Lector de Oráculos Angelicales</li><li> Numerologo </li><li>Constelador Familiar.</li><li>Flores de Bach</li></ul>', 'publicacion-614b7ab21412e.jpg', 0, '2021-09-22 06:00:00', '2024-12-04 03:10:30', '2021-09-22 06:00:00', 'egresado', 'activo', 7, 0),
	(102, 'Mariana Hernández Tenorio', 'mariana-hernandez-tenorio', 'Desde hace como 3 años, he tomado cursos en Tamashi, me encanta que son temas inovadores y aparte son temas que puedo utilizarlos en mi vida diaria, me han hechos crecer como persona. En mi trabajo me ha ayudado sobre todo el reiki para ser mas empatía con ellos.', '<ul><li>Maestra en 2 sistemas de Reiki (Japonés y Angélico)</li><li>Especialidades en : Reiki y Chamanismo</li><li>Lector de Oráculos Angelicales</li><li> Numerologo </li><li>Constelador Familiar.</li></ul>', 'publicacion-614b9920b1bb9.jpg', 0, '2021-09-22 06:00:00', '2024-12-04 03:10:30', '2021-09-22 06:00:00', 'egresado', 'activo', 8, 0),
	(103, 'María del Carmen Lema Pasantes', 'maria-del-carmen-lema-pasantes', 'Mi experiencia en Tamashi ha sido de mucho aprendizaje, divertida, relajante, terapéutica y de mucha paz. \r\nSe desarrolla la conciencia del aquí y el ahora, la intuición, se despiertan los sentidos y en cada una de las prácticas te liberas de lo que no sirve y renuevas energías. Abres tu mente a nuevos conocimientos que te permiten crecer y ampliar tu criterio. ', '<ul style="box-sizing: inherit; color: rgb(33, 37, 41); font-family: Nunito, " color=""><li style="box-sizing: inherit;">Maestra en 3 sistemas de Reiki (Japonés, tibetano-tantrico y Angélico)</li><li>Especialidades en : Cromoterapia, Reprogramación y Chamanismo</li><li style="box-sizing: inherit;">Reikista para mascotas.</li></ul>', 'publicacion-614bb1ac90a6d.jpg', 0, '2021-09-22 06:00:00', '2024-12-04 03:10:30', '2021-09-22 06:00:00', 'egresado', 'activo', 9, 0),
	(104, 'Oscar García García', 'oscar-garcia-garcia', 'Llegue “casualmente “ por qué quería comenzar a dar terapias de Reiki para generar un recurso extra, comencé, a las 2 semanas a ver cambios en mi vida personal en cuestiones de pareja principalmente, seguí cursando normal y aprendiendo cada clase algo nuevo sobre mi, las charlas con el Maestro y amigo José Luis eran muy enriquecedoras, me abrían los ojos y la conciencia, el aprendizaje  que fui acumulando me llenaba de fuerza y la energía que apenas  podía percibir me iba vislumbrando un nuevo camino, sin darme cuenta, después de 3 meses recuerdo bien, surge una separación con mi pareja después de vivir 5 años juntos para mi eso ya era mucho tiempo, primero me enojé y recuerdo que reclame  que si para eso había entrado al Reiki para deshacer mi vida y mi estabilidad emocional pasaron dos clases más y comencé a entender lo que estaba pasando, no fue nada fácil, no ha sido nada fácil y algunas veces quiero desistir, pero te comparto que hoy por hoy, sigo trabajando y lo seguiré haciendo por qué me siento feliz,  de algo estoy seguro, haber estudiado Reiki ha sido lo mejor que me ha pasado, logre alcanzar un grado más de conciencia, me encontré a mi mismo, vivo en paz y armonía, vivo en abundancia,  pero sobre todo poder servirle a alguien más para encontrar su camino eso no tiene precio, el servicio llena de amor mi corazón, agradezco el tiempo de mi Maestro José Luis por su empeño en cada clase, por darme su tiempo, su regaño y su energía cuando llego capa caída, gracias por todo este camino juntos, bendiciones ', '<p>Maestro Reiki Japonés <br></p>', 'publicacion-614d3f77ef45a.jpg', 0, '2021-09-23 06:00:00', '2024-12-04 03:10:30', '2021-09-23 06:00:00', 'egresado', 'activo', 10, 0),
	(105, 'Anayeli Rosas Medina', 'anayeli-rosas-medina', 'Soy Anayeli, llegué a Tamashi hace aproximadamente 8 años. Y estoy infinitamente agradecida con la vida, con Dios y con el centro Holístico Tamashi,  gracias a esa primer terapia que tomé mi vida, no volvió a ser la misma. \r\n\r\nHe estado ahí, como paciente, como alumna,  como consteladora. \r\n\r\nLas terapias son precisas, recibes lo que necesitas recibir, escuchas lo que necesitas escuchar (aunque no sea  precisamente lo que a veces quisieras oír), sin embargo, cuando logras superar la "crisis curativa", entiendes y agradeces, ves las cosas desde otro punto de vista. \r\n\r\nLos cursos son, el mejor espacio que he tenido para reencontrarme, a través del aprendizaje,  escuchar vivencias de los compañeros, he logrado entender aspectos de mi vida y con ello, tener herramientas para trabajar y sanar lo que tenga que sanar, teniendo claro que todo proceso tiene su tiempo y su espacio. \r\n\r\nDefinitivamente, Tamashi para mí, es y siempre será el espacio en el que encuentro paz, tranquilidad y  transformación, es el lugar que me ha permitido re dirigir mi vida en aras de vivirla  mejor día a día. \r\n\r\nAños después, reconozco que tengo temas pendientes por sanar, pero ahora ya no lo vivo desde el dolor, sino desde la gratitud, sabiendo que todo tiene su tiempo perfecto.\r\n\r\nAgradecida de corazón con José Luis por todo lo que me ha permitido aprender de él. Dios le conceda muchos años de salud y prosperidad, para poder seguir aprendiendo de él, gracias por ser un guía e inspiración en esta vida.', '<ul><li>Maestra en 3 sistemas de Reiki (Japonés, Angélico, Karuna)</li><li> Lector de Registros Akashicos</li><li> Tarotista</li><li>Constelador Familiar.</li></ul>', 'publicacion-6153770f43cb7.jpg', 0, '2021-09-28 06:00:00', '2024-12-04 03:10:30', '2021-09-28 06:00:00', 'egresado', 'activo', 11, 0),
	(106, 'Adriana Anaya Zamora', 'adriana-anaya-zamora', 'Sin saber que lo buscaba un día llegué acompañando a una amiga a realizar el curso de costuras del alma, en ese fin de semana me di cuenta que era momento de trabajar mi espiritualidad, ya no hubo vuelta atrás, junto con mi maestro José Luis iniciamos en el camino del despertar espiritual. Hoy no tengo mas.que agradecerle por quitarme la frialdad mental en la que vivía y por enseñarme a abrir mi corazón hacía todo y todos los que me rodean, en Tamashi encontré como amarme para poder amar a los demás.', '<ul><li>Maestra en 4 sistemas de Reiki (Japonés, tibetano-tantrico, Angélico, Karuna)</li><li>Especialidades en : Cromoterapia, Reprogramación y Chamanismo</li><li> Lector de Registros Akashicos</li><li> Tarotista</li><li>Lector de Oráculos Angelicales</li><li> Numerologo </li><li>Constelador Familiar.</li><li>Flores de Bach</li></ul>', 'publicacion-615391b107ef1.jpg', 0, '2021-09-28 06:00:00', '2024-12-04 03:10:30', '2021-09-28 06:00:00', 'egresado', 'activo', 12, 0),
	(107, 'Arturo Nava Trujillo', 'arturo-nava-trujillo', 'Como empezar una historia de vida en donde te reencuentras contigo mismo y con tu energía, encuentras ayuda y apoyo incondicional de tu maestro que con el tiempo se vuelve amistad. Yo solo puedo agradecerle a la vida haberme llevado a las manos de Reiki tamashi.', '<p>Maestro Reiki Japones </p><p>Cromoterapeuta.<br></p><p>Maestro en Reiki para Animales<br></p><p>Numerólogo<br></p>', 'publicacion-616e3b083d096.jpg', 0, '2021-10-18 06:00:00', '2024-12-04 03:10:30', '2021-10-18 06:00:00', 'egresado', 'activo', 13, 0),
	(108, 'Mario Raúl Nava Fonseca', 'mario-raul-nava-fonseca', 'Caí en la profundidad de no saber hacia donde iba, sentía que no había salida, sin saber lo que quería encontré a Tamashi un día. Le agradezco a mi maestro José Luis Escobar, a Dios, a la Virgen y los arcángeles por ayudarme a entender el camino del bien sin esperar nada a cambio.', '<ul><li>Maestro en 2sistemas de Reiki (Japonesa, Angélico,)</li><li>Especialidades en : Chamanismo</li><li>Lector de Registros Akashicos</li><li>Numerólogo</li></ul>', 'publicacion-616f5e2df32cc.jpg', 0, '2021-10-19 06:00:00', '2024-12-04 03:10:30', '2021-10-19 06:00:00', 'egresado', 'activo', 14, 0),
	(109, 'Curso de Numerología Tántrica', 'curso-de-numerologia-tantrica', '“Cada número que te acompaña desde tu nacimiento es un susurro del Universo, una llave sagrada que revela quién eres y hacia dónde camina tu espíritu.”\r\n\r\n', '<p>\r\n\r\n</p><p data-start="73" data-end="127"><strong data-start="73" data-end="125"><span style="font-size: 18px;">Numerología Tántrica – El mapa sagrado de tu ser</span></strong></p><p data-start="129" data-end="429"><span style="font-size: 18px;">La </span><strong data-start="132" data-end="156"><span style="font-size: 18px;">Numerología Tántrica</span></strong><span style="font-size: 18px;"> es una herramienta espiritual que, a través de tu fecha de nacimiento, revela la sabiduría oculta de tu alma. Cada número es una llave que abre la comprensión de tus dones, retos y aprendizajes, mostrándote el camino hacia tu crecimiento interior y tu propósito de vida.</span></p><p data-start="431" data-end="615"><span style="font-size: 18px;">Tomar este curso es regalarte la oportunidad de </span><strong data-start="479" data-end="507"><span style="font-size: 18px;">conocerte en profundidad</span></strong><span style="font-size: 18px;">, sanar aspectos del pasado, descubrir tus potenciales y aprender a ver tu vida con mayor claridad y amor.</span></p><p class="MsoNormal"><span style="font-size: 18px;">\r\n</span><span style="font-size: 18px;">\r\n</span><span style="font-size: 18px;">\r\n</span></p><p data-start="617" data-end="777"><span style="font-size: 18px;">La Numerología Tántrica no solo te ofrece respuestas; te brinda un mapa para transformar tu vida y ayudar a otros en su propio camino de evolución espiritual.</span></p><p class="MsoNormal"><span style="font-size: 18px;">Al tomar este curso, abrirás un portal de sabiduría para ti y para otros, aprendiendo a interpretar este lenguaje sagrado y a caminar con mayor claridad, paz y amor en tu camino espiritual.</span></p><p class="MsoNormal"><span style="font-size: 18px;"><br></span></p><p class="MsoNormal"><b>Numerología Tántrica (Temario)</b><br></p>\r\n\r\n<p class="MsoNormal">1.- Concepto de Numerología</p>\r\n\r\n<p class="MsoNormal">2.- Numerología de Ailexin ( Numerología tántrica)</p>\r\n\r\n<p class="MsoNormal">3.- Cinco Aspectos a estudiar de la una Numerología\r\nPersonalizada</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;text-indent:\r\n35.4pt;line-height:normal">3.1. Alma</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;text-indent:\r\n35.4pt;line-height:normal">3.2 Personalidad</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;text-indent:\r\n35.4pt;line-height:normal">3.3 Regalo de Dios</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;text-indent:\r\n35.4pt;line-height:normal">3.4 Vida Pasada</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;text-indent:\r\n35.4pt;line-height:normal">3.5 Misión</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;text-indent:\r\n35.4pt;line-height:normal">&nbsp;</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal"><span style="mso-spacerun:yes">&nbsp;</span>4.- Tipos de Numerología</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">&nbsp;</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;text-indent:\r\n35.4pt;line-height:normal">4.1 Reflexiva</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;text-indent:\r\n35.4pt;line-height:normal">4.2 Dharmatica</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;text-indent:\r\n35.4pt;line-height:normal">4.3 Karmatica</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">&nbsp;</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">5.- Características de los números del 1 al 11</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">&nbsp;</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">5.1 Numero en Positivo</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">5.2 Número en Negativo </p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">5.3 Numero en estado Perfecto</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">5.4 Numero en cada Aspecto (Alma, Personalidad, Regalo de Dios, Vida Pasada,\r\nMisión) </p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">&nbsp;</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">&nbsp;</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">6.- Números Maestros</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">&nbsp;</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">7.-Elaboración, análisis e interpretación del Estudio Numerológico</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal"><span style="mso-spacerun:yes">&nbsp;</span></p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">8- Enfermedades y numerología</p>\r\n\r\n<p class="MsoNormal" style="margin-bottom:0cm;margin-bottom:.0001pt;line-height:\r\nnormal">&nbsp;</p>\r\n\r\n<span style="font-size:11.0pt;line-height:107%;font-family:" calibri",sans-serif;="" mso-ascii-theme-font:minor-latin;mso-fareast-font-family:calibri;mso-fareast-theme-font:="" minor-latin;mso-hansi-theme-font:minor-latin;mso-bidi-font-family:"times="" new="" roman";="" mso-bidi-theme-font:minor-bidi;mso-ansi-language:es-mx;mso-fareast-language:="" en-us;mso-bidi-language:ar-sa"="">9.- Análisis e Interpretación de los números en\r\nlas relaciones familiares</span><p><!--[if gte mso 9]><xml>\r\n <o:OfficeDocumentSettings>\r\n  <o:AllowPNG></o:AllowPNG>\r\n </o:OfficeDocumentSettings>\r\n</xml><![endif]--><!--[if gte mso 9]><xml>\r\n <w:WordDocument>\r\n  <w:View>Normal</w:View>\r\n  <w:Zoom>0</w:Zoom>\r\n  <w:TrackMoves></w:TrackMoves>\r\n  <w:TrackFormatting></w:TrackFormatting>\r\n  <w:HyphenationZone>21</w:HyphenationZone>\r\n  <w:PunctuationKerning></w:PunctuationKerning>\r\n  <w:ValidateAgainstSchemas></w:ValidateAgainstSchemas>\r\n  <w:SaveIfXMLInvalid>false</w:SaveIfXMLInvalid>\r\n  <w:IgnoreMixedContent>false</w:IgnoreMixedContent>\r\n  <w:AlwaysShowPlaceholderText>false</w:AlwaysShowPlaceholderText>\r\n  <w:DoNotPromoteQF></w:DoNotPromoteQF>\r\n  <w:LidThemeOther>ES-MX</w:LidThemeOther>\r\n  <w:LidThemeAsian>X-NONE</w:LidThemeAsian>\r\n  <w:LidThemeComplexScript>X-NONE</w:LidThemeComplexScript>\r\n  <w:Compatibility>\r\n   <w:BreakWrappedTables></w:BreakWrappedTables>\r\n   <w:SnapToGridInCell></w:SnapToGridInCell>\r\n   <w:WrapTextWithPunct></w:WrapTextWithPunct>\r\n   <w:UseAsianBreakRules></w:UseAsianBreakRules>\r\n   <w:DontGrowAutofit></w:DontGrowAutofit>\r\n   <w:SplitPgBreakAndParaMark></w:SplitPgBreakAndParaMark>\r\n   <w:EnableOpenTypeKerning></w:EnableOpenTypeKerning>\r\n   <w:DontFlipMirrorIndents></w:DontFlipMirrorIndents>\r\n   <w:OverrideTableStyleHps></w:OverrideTableStyleHps>\r\n  </w:Compatibility>\r\n  <m:mathPr>\r\n   <m:mathFont m:val="Cambria Math"></m:mathFont>\r\n   <m:brkBin m:val="before"></m:brkBin>\r\n   <m:brkBinSub m:val="--"></m:brkBinSub>\r\n   <m:smallFrac m:val="off"></m:smallFrac>\r\n   <m:dispDef></m:dispDef>\r\n   <m:lMargin m:val="0"></m:lMargin>\r\n   <m:rMargin m:val="0"></m:rMargin>\r\n   <m:defJc m:val="centerGroup"></m:defJ