rity="46"\r\n   Name="List Table 1 Light Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="47" Name="List Table 2 Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="48" Name="List Table 3 Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="49" Name="List Table 4 Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="50" Name="List Table 5 Dark Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="51"\r\n   Name="List Table 6 Colorful Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" Priority="52"\r\n   Name="List Table 7 Colorful Accent 6"></w:LsdException>\r\n  <w:LsdException Locked="false" SemiHidden="true" UnhideWhenUsed="true"\r\n   Name="Mention"></w:LsdException>\r\n  <w:LsdException Locked="false" SemiHidden="true" UnhideWhenUsed="true"\r\n   Name="Smart Hyperlink"></w:LsdException>\r\n  <w:LsdException Locked="false" SemiHidden="true" UnhideWhenUsed="true"\r\n   Name="Hashtag"></w:LsdException>\r\n  <w:LsdException Locked="false" SemiHidden="true" UnhideWhenUsed="true"\r\n   Name="Unresolved Mention"></w:LsdException>\r\n </w:LatentStyles>\r\n</xml><![endif]--><!--[if gte mso 10]>\r\n<style>\r\n /* Style Definitions */\r\n table.MsoNormalTable\r\n	{mso-style-name:"Tabla normal";\r\n	mso-tstyle-rowband-size:0;\r\n	mso-tstyle-colband-size:0;\r\n	mso-style-noshow:yes;\r\n	mso-style-priority:99;\r\n	mso-style-parent:"";\r\n	mso-padding-alt:0cm 5.4pt 0cm 5.4pt;\r\n	mso-para-margin-top:0cm;\r\n	mso-para-margin-right:0cm;\r\n	mso-para-margin-bottom:8.0pt;\r\n	mso-para-margin-left:0cm;\r\n	line-height:107%;\r\n	mso-pagination:widow-orphan;\r\n	font-size:11.0pt;\r\n	font-family:"Calibri",sans-serif;\r\n	mso-ascii-font-family:Calibri;\r\n	mso-ascii-theme-font:minor-latin;\r\n	mso-hansi-font-family:Calibri;\r\n	mso-hansi-theme-font:minor-latin;\r\n	mso-bidi-font-family:"Times New Roman";\r\n	mso-bidi-theme-font:minor-bidi;\r\n	mso-fareast-language:EN-US;}\r\n</style>\r\n<![endif]-->\r\n\r\n</p>\r\n\r\n<p class="MsoNormal"><b><span style="font-size: 14px;">Descubre la Magia de la Angelología y la Angeloterapia</span></b><span style="font-size: 18px;">﻿</span></p><p class="MsoNormal"><br></p><p class="MsoNormal">La Angelología es el estudio sagrado de los ángeles, seres de luz y amor divino que nos acompañan en nuestro camino espiritual. A través de ella, aprendemos quiénes son, cómo se comunican con nosotros y de qué manera pueden guiarnos hacia una vida llena de paz, propósito y plenitud.</p><p class="MsoNormal">La Angeloterapia, por su parte, es una hermosa herramienta de sanación espiritual y energética. Nos conecta con la energía angelical para liberar bloqueos emocionales, recibir claridad en momentos de confusión y abrazar la serenidad que nuestro corazón anhela.</p><p class="MsoNormal">Ambos cursos son una invitación a abrir tu corazón, elevar tu conciencia y recordar que nunca caminas solo: los ángeles están contigo, listos para ayudarte a transformar tu vida con su amor incondicional.</p><p class="MsoNormal">Permítete vivir esta experiencia mágica y deja que la luz angelical ilumine cada aspecto de tu ser.</p><p class="MsoNormal">Obtendrás dos certificaciones:</p>\r\n\r\n<p class="MsoListParagraphCxSpFirst" style="text-indent:-18.0pt;mso-list:l1 level1 lfo3"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">1.<span style="font:7.0pt " times="" new="" roman""="">      1.  </span></span></span><b>Angelólogia</b></p>\r\n\r\n<p class="MsoListParagraphCxSpMiddle"> Temario: <br></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ul><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">1.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>¿Que son los Ángeles?</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">2.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Los ángeles en la antigüedad (Historia Angelical\r\n)</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">3.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Jerarquía Angelical</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">4.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Los siete cielos</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">5.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Ángeles de la Guarda</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">6.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Los 7 arcángeles principales </li></ul><p class="MsoListParagraphCxSpLast" style="text-indent:-18.0pt;mso-list:l4 level1 lfo4"><br></p>\r\n\r\n<p class="MsoNormal">2. <b>Angeloterapeuta</b></p>\r\n\r\n<p class="MsoNormal">Temario:</p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ul><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">1.<span style="font:7.0pt " times="" new="" roman""="">        </span></span></span>¿Qué es y como funciona la Angeloterapia?</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">2.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Actitudes de un Angeloterapeuta</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">3.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Como se lleva a cabo una Angeloterapia</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">4.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Revisión de Chacras por medio del escaneo</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">5.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Canalización de Mensajes Angelicales (Mediumnidad)</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">6.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Sanación con la ayuda de los Arcángeles.</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">7.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Uso de Velas como apoyo al trabajo angelical.</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">8.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Que es la intuición</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">9.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Las 4 claris (Dones espirituales)</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">10.<span style="font:7.0pt " times="" new="" roman""="">  \r\n</span></span></span>Clarisentencia</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">11.<span style="font:7.0pt " times="" new="" roman""="">  \r\n</span></span></span>Uso de 62 símbolos Angélicos.</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">12.<span style="font:7.0pt " times="" new="" roman""="">  \r\n</span></span></span>Elaboración de Altar angélico.</li><li style="text-indent: -18pt;">13    Protocolos de Terapias por diferentes temas.</li><li>Entre otros. <br></li></ul>\r\n\r\n<p class="MsoNormal">Además de aprender a trabajar:</p>\r\n\r\n<p class="MsoListParagraphCxSpFirst" style="text-indent:-18.0pt;mso-list:l3 level1 lfo2"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">A.<span style="font:7.0pt " times="" new="" roman""="">     \r\n</span></span></span><b>Magia Angelical.</b></p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n<ul><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">1.     </span></span>Oración</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">2.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Invocación</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">3.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Evocación</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">4.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Rituales para trabajar diferentes situaciones</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">5.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Los ángeles y el Zodiaco</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">6.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Los ángeles y las estaciones del año</li><li style="text-indent: -18pt;"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">7.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Los ángeles y los 4 elementos</li></ul>\r\n\r\n<p class="MsoListParagraphCxSpMiddle" style="text-indent:-18.0pt;mso-list:l0 level1 lfo5"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">8.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span>Entre otros.</p>\r\n\r\n\r\n\r\n<p class="MsoListParagraphCxSpMiddle" style="text-indent:-18.0pt;mso-list:l3 level1 lfo2"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">B.<span style="font:7.0pt " times="" new="" roman""="">        </span></span></span><b>Meditaciones Angelicales</b></p>\r\n\r\n<p class="MsoListParagraphCxSpMiddle" style="text-indent:-18.0pt;mso-list:l3 level1 lfo2"><span style="mso-bidi-font-family:Calibri;mso-bidi-theme-font:minor-latin"><span style="mso-list:Ignore">C.<span style="font:7.0pt " times="" new="" roman""="">      \r\n</span></span></span><b>Oraciones para los Arcángeles</b></p>\r\n\r\n\r\n\r\n<p class="MsoNormal">Y podrás tener una tercera certificación como <b>ANGELOTERAPEUTA\r\nMASTER</b> si ya cuentas con los cursos de:</p>\r\n\r\n<p class="MsoNormal">1.<span style="mso-tab-count:1">          <b> </b></span><b>Oráculos\r\nAngelicales</b> <br></p>\r\n\r\n<p class="MsoNormal">2.<span style="mso-tab-count:1">          <b> </b></span><b>Talismanes\r\nAngélicos</b> <span style="mso-spacerun:yes"> </span></p>\r\n\r\n<p class="MsoNormal">3.<span style="mso-tab-count:1">          <b> </b></span><b>Reiki\r\nAngélico</b> <span style="mso-spacerun:yes"> </span><span style="mso-spacerun:yes"> </span></p>\r\n\r\n', 'publicacion-64f3eafca1513.jpg', 0, '2023-09-02 06:00:00', '2026-04-04 22:01:10', '2023-09-02 06:00:00', 'cursos', 'activo', 1, 1),
	(129, 'Práctica de Reiki 2023 ', 'practica-de-reiki-2023', 'Práctica de Reiki llamada Amor Incondional, en donde iluminamos todos los cuerpos de la persona para llenarlo de la Energía de Reiki y Amor Incondiconal', '', 'publicacion-64f8f7e4d91cc.jpg', 0, '2023-09-06 06:00:00', '2025-11-25 17:33:32', '2023-09-06 06:00:00', 'galeria', 'activo', 21, 0),
	(130, 'Sanación de Aura con Reiki 2023', 'sanacion-de-aura-con-reiki-2023', '', '', 'publicacion-64f8f9871f9b8.jpg', 0, '2023-09-06 06:00:00', '2025-11-25 17:33:32', '2023-09-06 06:00:00', 'galeria', 'activo', 22, 0),
	(131, 'Angeloterapia 2023 ', 'angeloterapia-2023', 'Conectando con los Arcángeles ', '', 'publicacion-64f8fcb1abee8.jpg', 0, '2023-09-06 06:00:00', '2025-11-25 17:33:32', '2023-09-06 06:00:00', 'galeria', 'activo', 23, 0),
